INSERT INTO `berita` (`id_berita`, `id_user`, `id_kategori`, `slug_berita`, `judul_berita`, `ringkasan`, `isi`, `status_berita`, `jenis_berita`, `keywords`, `gambar`, `icon`, `hits`, `urutan`, `tanggal_post`, `tanggal_publish`, `tanggal`) VALUES
(1, 1, 10, 'smk-1-java-web-media-membuka-penerimaan-siswa-baru-untuk-tahun-ajaran-2024-2025', 'SMK 1 Java Web Media Membuka Penerimaan Siswa Baru untuk Tahun Ajaran 2024-2025', 'SMK 1 Java Web Media, sebuah lembaga pendidikan unggulan yang fokus pada bidang Java Web Media, dengan gembira mengumumkan pembukaan penerimaan siswa baru untuk tahun ajaran mendatang. ', '<p>SMK 1 Java Web Media, sebuah lembaga pendidikan unggulan yang fokus pada bidang Java Web Media, dengan gembira mengumumkan pembukaan penerimaan siswa baru untuk tahun ajaran mendatang. Penerimaan siswa baru ini bertujuan untuk memberikan kesempatan kepada para calon siswa yang berminat mengembangkan keterampilan dan pengetahuan di dunia teknologi informasi, terutama dalam pengembangan web menggunakan bahasa pemrograman Java. Dengan kurikulum yang terkini dan fasilitas yang memadai, SMK 1 Java Web Media siap menyambut generasi baru yang bersemangat untuk mengukir prestasi di dunia industri digital.</p>\r\n<p>Pendaftaran dapat dilakukan secara online melalui situs resmi SMK 1 Java Web Media mulai tanggal 1 Februari hingga 15 Maret 2024. Calon siswa dapat memilih dari berbagai program studi yang ditawarkan, termasuk pengembangan web, desain grafis digital, dan manajemen media digital. Selain itu, SMK 1 Java Web Media juga menawarkan bantuan beasiswa bagi siswa berprestasi dan berkeinginan kuat untuk mengejar karir di dunia teknologi informasi.</p>\r\n<p>Sebagai sekolah yang komitmen terhadap kualitas pendidikan, SMK 1 Java Web Media menjamin pembelajaran yang interaktif, didukung oleh pengajar berpengalaman, fasilitas modern, dan program praktek kerja. Dengan membuka pintu selebar-lebarnya untuk para calon siswa, SMK 1 Java Web Media berharap dapat berperan aktif dalam mencetak generasi muda yang siap bersaing dan berkontribusi dalam industri Java Web Media yang terus berkembang.</p>', 'Publish', 'Berita', 'SMK 1 Java Web Media, sebuah lembaga pendidikan unggulan yang fokus pada bidang Java Web Media, dengan gembira mengumumkan pembukaan penerimaan siswa baru untuk tahun ajaran mendatang. Penerimaan siswa baru ini bertujuan untuk memberikan kesempatan kepada para calon siswa yang berminat mengembangkan keterampilan dan pengetahuan di dunia teknologi informasi, terutama dalam pengembangan web menggunakan bahasa pemrograman Java. ', '1705909421_ff7657faaf9335018928.jpg', '', 7, 0, '2024-01-17 04:50:05', '2024-01-17 04:49:00', '2026-03-10 13:07:25'),
(2, 11, 10, 'sejarah-pondok-pesantren-al-hikamussalafie', 'SEJARAH PONDOK PESANTREN AL-HIKAMUSSALAFIE', 'Sejarah Pondok Pesantren Al-Hikamussalafie', '<section id=\"profil-pesantren\" style=\"max-width: 1100px; margin: 0 auto; font-family: \'Segoe UI\', \'Poppins\', system-ui, -apple-system, sans-serif; background: #ffffff; border-radius: 28px; box-shadow: 0 20px 40px rgba(0,0,0,0.05); overflow: hidden;\">\r\n    \r\n    <!-- Header dengan latar gradien hijau -->\r\n    <header style=\"background: linear-gradient(135deg, #1e6b3e, #0f4a2a); padding: 45px 30px 40px; text-align: center; color: white;\">\r\n        <div style=\"font-size: 48px; margin-bottom: 15px;\">\r\n            <i class=\"fas fa-mosque\" style=\"background: rgba(255,255,255,0.15); padding: 12px 20px; border-radius: 60px;\"></i>\r\n        </div>\r\n    <h1 style=\"font-size: 2.2rem; margin: 0 0 12px 0; font-weight: 700; letter-spacing: -0.5px; color: white;\">\r\n    Pondok Pesantren Al Hikamussalafie\r\n</h1>\r\n        <p style=\"font-size: 0.95rem; opacity: 0.9; margin: 0; border-top: 1px solid rgba(255,255,255,0.3); display: inline-block; padding-top: 12px;\">\r\n            <i class=\"fas fa-quote-left\"></i> \"Mencetak Generasi Berilmu, Beriman, dan Berakhlakul Karimah\" <i class=\"fas fa-quote-right\"></i>\r\n        </p>\r\n    </header>\r\n\r\n    <!-- Badge info singkat -->\r\n    <div style=\"display: flex; flex-wrap: wrap; gap: 16px; background: #fef9ef; padding: 18px 28px; border-bottom: 1px solid #e9e0d0;\">\r\n        <div style=\"display: flex; align-items: center; gap: 10px;\">\r\n            <span style=\"background: #1e6b3e; width: 32px; height: 32px; display: inline-flex; align-items: center; justify-content: center; border-radius: 50%; color: white;\"><i class=\"fas fa-calendar-alt\"></i></span>\r\n            <span><strong style=\"color: #2c5a3a;\">Berdiri:</strong> 14 Januari 1996 M / 23 Sya\'ban 1416 H</span>\r\n        </div>\r\n        <div style=\"display: flex; align-items: center; gap: 10px;\">\r\n            <span style=\"background: #1e6b3e; width: 32px; height: 32px; display: inline-flex; align-items: center; justify-content: center; border-radius: 50%; color: white;\"><i class=\"fas fa-map-marker-alt\"></i></span>\r\n            <span><strong style=\"color: #2c5a3a;\">Lokasi:</strong> Kampung Tanjungsari, Cipunagara, Subang</span>\r\n        </div>\r\n        <div style=\"display: flex; align-items: center; gap: 10px;\">\r\n            <span style=\"background: #1e6b3e; width: 32px; height: 32px; display: inline-flex; align-items: center; justify-content: center; border-radius: 50%; color: white;\"><i class=\"fas fa-history\"></i></span>\r\n            <span><strong style=\"color: #2c5a3a;\">Nama Awal:</strong> Ponpes Syarif Hidayatullah</span>\r\n        </div>\r\n    </div>\r\n\r\n    <!-- Konten Sejarah Utama -->\r\n    <article style=\"padding: 35px 32px; line-height: 1.85; color: #2c3e2f; background: #fffefb;\">\r\n        \r\n        <!-- Paragraf 1: Berdiri & nama awal -->\r\n        <p style=\"margin-bottom: 20px; font-size: 1rem; text-align: justify;\">\r\n            <strong style=\"color: #1f6e43; font-size: 1.05rem;\"><i class=\"fas fa-landmark\"></i> Pondok Pesantren Al Hikamussalafie</strong> merupakan lembaga pendidikan Islam yang berdiri pada hari \r\n            <span style=\"background: #e8f0e5; padding: 2px 10px; border-radius: 20px; font-weight: 600;\"><i class=\"fas fa-moon\"></i> Ahad, 23 Sya\'ban 1416 H</span>, \r\n            bertepatan dengan tanggal <span style=\"background: #e8f0e5; padding: 2px 10px; border-radius: 20px; font-weight: 600;\"><i class=\"fas fa-sun\"></i> 14 Januari 1996 M</span>. \r\n            Pada awal berdirinya, pesantren ini menggunakan nama <strong style=\"color: #b95f1a;\"><i class=\"fas fa-tag\"></i> Pondok Pesantren Syarif Hidayatullah</strong>.\r\n        </p>\r\n\r\n        <!-- Paragraf 2: Latar belakang kondisi masyarakat -->\r\n        <p style=\"margin-bottom: 20px; text-align: justify;\">\r\n            <i class=\"fas fa-place-of-worship\"></i> Latar belakang berdirinya pesantren ini tidak terlepas dari kondisi masyarakat pada saat itu. Di wilayah \r\n            <strong><i class=\"fas fa-location-dot\"></i> Kampung Tanjungsari RT 21 RW 07, Desa Tanjung, Kecamatan Cipunagara, Kabupaten Subang</strong>, \r\n            masih terdapat berbagai praktik kemusyrikan yang cukup kuat. Salah satunya adalah adanya kepercayaan masyarakat terhadap \r\n            sebuah sumur keramat yang dikenal dengan sebutan <strong style=\"color: #b95f1a;\"><i class=\"fas fa-water\"></i> Sumur Kidul</strong>. \r\n            Banyak masyarakat yang datang untuk melakukan ritual tertentu di tempat tersebut.\r\n        </p>\r\n\r\n        <!-- Box khusus: Fenomena Sumur Kidul & Kesurupan -->\r\n        <div style=\"background: linear-gradient(115deg, #fef5e6, #fffaf0); border-left: 5px solid #d49b3a; border-radius: 20px; padding: 20px 25px; margin: 28px 0; display: flex; gap: 18px; flex-wrap: wrap;\">\r\n            <div style=\"font-size: 2.2rem; min-width: 55px; text-align: center;\">\r\n                <i class=\"fas fa-hands-praying\" style=\"color: #b45f2a;\"></i>\r\n            </div>\r\n            <div style=\"flex: 1;\">\r\n                <h4 style=\"margin: 0 0 8px 0; color: #b45f2a; font-size: 1.2rem;\"><i class=\"fas fa-exclamation-triangle\"></i> Fenomena Sumur Kidul & Kesurupan Massal</h4>\r\n                <p style=\"margin: 0; line-height: 1.65; text-align: justify;\">\r\n                    <i class=\"fas fa-cloud-moon\"></i> Pada masa itu juga sering terjadi peristiwa kesurupan yang hampir terjadi setiap malam, bahkan dalam satu malam bisa mencapai dua hingga tiga orang. \r\n                    Selain itu, hampir setiap bulan terdapat kabar duka dengan meninggalnya beberapa warga. \r\n                    Kondisi tersebut menimbulkan keresahan mendalam di tengah masyarakat.\r\n                </p>\r\n            </div>\r\n        </div>\r\n\r\n        <!-- Paragraf 3: Santri berjuang -->\r\n        <p style=\"margin-bottom: 20px; text-align: justify;\">\r\n            <i class=\"fas fa-quran\"></i> Para santri yang pada waktu itu berusaha menghadapi kondisi tersebut dengan membaca Al-Qur\'an dan melakukan berbagai amalan keagamaan. \r\n            Namun usaha tersebut sering kali tidak dihargai oleh sebagian masyarakat, bahkan keberadaan santri dan kegiatan keagamaan yang dilakukan kurang mendapat perhatian.\r\n        </p>\r\n\r\n        <!-- Paragraf 4: Tekad mendirikan pesantren -->\r\n        <p style=\"margin-bottom: 20px; text-align: justify;\">\r\n            <i class=\"fas fa-heart\" style=\"color: #e67e22;\"></i> Melihat kondisi tersebut, muncul tekad dan doa yang kuat kepada Allah SWT agar diberikan jalan untuk memperbaiki keadaan masyarakat melalui pendidikan agama. \r\n            Dari sinilah lahir keputusan untuk mendirikan sebuah <strong><i class=\"fas fa-mosque\"></i> pondok pesantren</strong> yang menjadi pusat pembelajaran ilmu agama Islam dan pembinaan akhlak bagi masyarakat sekitar.\r\n        </p>\r\n\r\n        <!-- Paragraf 5: Awal kegiatan di rumah orang tua (icon rumah di tengah) -->\r\n        <div style=\"background: #f4f0e8; border-radius: 24px; padding: 18px 24px; margin: 25px 0;\">\r\n            <div style=\"text-align: center; margin-bottom: 15px;\">\r\n                <div style=\"font-size: 2.5rem; display: inline-block; background: #e6d9c6; width: 70px; height: 70px; line-height: 70px; text-align: center; border-radius: 50%;\">\r\n                    <i class=\"fas fa-home\" style=\"color: #2d6a4f;\"></i>\r\n                </div>\r\n            </div>\r\n            <div>\r\n                <p style=\"margin: 0 0 8px 0; font-weight: 700; color: #2d6a4f; text-align: center; font-size: 1.1rem;\">\r\n                    <i class=\"fas fa-chalkboard-user\"></i> Awal Kegiatan Belajar Mengajar\r\n                </p>\r\n                <p style=\"margin: 6px 0 0 0; text-align: justify;\">\r\n                    Pada masa awal berdirinya, kegiatan belajar mengajar pesantren dilaksanakan di rumah orang tua pendiri, yaitu \r\n                    <strong><i class=\"fas fa-user-graduate\"></i> Bapak H. Mohammad Nur bin Sukrad</strong> dan <strong><i class=\"fas fa-user-graduate\"></i> Ibu Hj. Siti Wasri binti Saryad</strong>. \r\n                    Dari tempat sederhana inilah proses pendidikan Islam dimulai dengan penuh keikhlasan dan semangat dakwah.\r\n                </p>\r\n            </div>\r\n        </div>\r\n\r\n        <!-- Paragraf 6: Perkembangan pesantren -->\r\n        <p style=\"margin-bottom: 20px; text-align: justify;\">\r\n            <i class=\"fas fa-chart-line\"></i> Seiring berjalannya waktu, kegiatan pendidikan di pesantren berjalan dengan baik dan mendapat dukungan dari masyarakat. \r\n            Para santri mulai berdatangan untuk menimba ilmu agama, khususnya dalam mempelajari \r\n            <strong><i class=\"fas fa-book-quran\"></i> Al-Qur\'an</strong> dan <strong><i class=\"fas fa-book\"></i> kitab-kitab klasik (kitab kuning)</strong> dengan metode pembelajaran khas pesantren salaf.\r\n        </p>\r\n\r\n        <!-- Perubahan Nama (Feature Card) -->\r\n        <div style=\"background: #e6e2d6; border-radius: 28px; padding: 25px; text-align: center; margin: 35px 0;\">\r\n            <div style=\"font-size: 0.9rem; color: #6f4f2a;\"><i class=\"fas fa-tags\"></i> Transformasi Identitas</div>\r\n            <div style=\"font-size: 1.1rem; text-decoration: line-through; opacity: 0.7; margin: 10px 0 5px;\"><i class=\"fas fa-mosque\"></i> Pondok Pesantren Syarif Hidayatullah</div>\r\n            <div style=\"font-size: 1.8rem; font-weight: 800; color: #1e6b3e; margin: 8px 0;\"><i class=\"fas fa-arrow-down\"></i> <i class=\"fas fa-arrow-down\"></i> <i class=\"fas fa-arrow-down\"></i></div>\r\n            <div style=\"font-size: 1.5rem; font-weight: 800; color: #2a5a3a; letter-spacing: 1px;\"><i class=\"fas fa-star-and-crescent\"></i> Pondok Pesantren Al Hikamussalafie</div>\r\n            <div style=\"margin-top: 15px;\">\r\n                <span style=\"background: #fff1e0; padding: 6px 18px; border-radius: 40px; font-size: 0.8rem; font-weight: 500;\">\r\n                    <i class=\"far fa-calendar-alt\"></i> 10 Januari 2015 M · 19 Rabiul Awal 1436 H\r\n                </span>\r\n            </div>\r\n            <p style=\"margin-top: 14px; font-size: 0.85rem; color: #5a3e20;\">\r\n                <i class=\"fas fa-gem\"></i> Perubahan nama ini dilakukan sebagai bagian dari pengembangan lembaga dan identitas pesantren yang lebih kuat dalam menjaga tradisi keilmuan Islam salaf.\r\n            </p>\r\n        </div>\r\n\r\n        <!-- Paragraf 7: Yayasan & Unit Pendidikan -->\r\n        <p style=\"margin-bottom: 20px; text-align: justify;\">\r\n            <i class=\"fas fa-church\"></i> Hingga saat ini, Pondok Pesantren Al Hikamussalafie terus berkembang dan berperan aktif dalam bidang pendidikan dan dakwah. \r\n            Lembaga ini berada di bawah naungan <strong style=\"color: #1f6e43;\"><i class=\"fas fa-building\"></i> Yayasan Al Hikamussalafie</strong> yang menaungi beberapa unit pendidikan, \r\n            di antaranya Pondok Pesantren Al Hikamussalafie serta <strong style=\"color: #1f6e43;\"><i class=\"fas fa-school\"></i> SMP Nusantara Cipunagara</strong>.\r\n        </p>\r\n\r\n        <!-- Grid: Kurikulum & Metode Pengajaran -->\r\n        <div style=\"display: flex; gap: 24px; flex-wrap: wrap; margin: 40px 0 30px;\">\r\n            <div style=\"flex: 1; min-width: 260px; background: #faf7f0; border-radius: 20px; padding: 22px 20px; border: 1px solid #e5d9c8;\">\r\n                <h3 style=\"color: #2a6b47; margin-top: 0; display: flex; align-items: center; gap: 10px;\">\r\n                    <i class=\"fas fa-book\" style=\"font-size: 1.6rem;\"></i> Kurikulum Salaf\r\n                </h3>\r\n                <ul style=\"list-style-type: none; padding-left: 0;\">\r\n                    <li style=\"margin-bottom: 10px;\"><i class=\"fas fa-check-circle\" style=\"color: #27ae60;\"></i> Kajian Kitab Klasik (Kitab Kuning)</li>\r\n                    <li style=\"margin-bottom: 10px;\"><i class=\"fas fa-check-circle\" style=\"color: #27ae60;\"></i> Tahsin & Tahfidz Al-Qur\'an</li>\r\n                    <li style=\"margin-bottom: 10px;\"><i class=\"fas fa-check-circle\" style=\"color: #27ae60;\"></i> Ilmu Alat: Nahwu & Shorof</li>\r\n                    <li style=\"margin-bottom: 10px;\"><i class=\"fas fa-check-circle\" style=\"color: #27ae60;\"></i> Dasar Keislaman: Fiqih, Tauhid, & Akhlak</li>\r\n                </ul>\r\n            </div>\r\n\r\n            <div style=\"flex: 1; min-width: 260px; background: #faf7f0; border-radius: 20px; padding: 22px 20px; border: 1px solid #e5d9c8;\">\r\n                <h3 style=\"color: #2a6b47; margin-top: 0; display: flex; align-items: center; gap: 10px;\">\r\n                    <i class=\"fas fa-chalkboard\" style=\"font-size: 1.6rem;\"></i> Metode Pengajaran\r\n                </h3>\r\n                <ul style=\"list-style-type: none; padding-left: 0;\">\r\n                    <li style=\"margin-bottom: 10px;\"><i class=\"fas fa-users\" style=\"color: #27ae60;\"></i> <strong>Bandongan:</strong> Pengajian kolektif</li>\r\n                    <li style=\"margin-bottom: 10px;\"><i class=\"fas fa-user-graduate\" style=\"color: #27ae60;\"></i> <strong>Sorogan:</strong> Bimbingan intensif perorangan</li>\r\n                    <li style=\"margin-bottom: 10px;\"><i class=\"fas fa-gavel\" style=\"color: #27ae60;\"></i> <strong>Disiplin:</strong> Pembinaan karakter & tanggung jawab</li>\r\n                </ul>\r\n            </div>\r\n        </div>\r\n\r\n        <!-- Sinergi Pendidikan Formal -->\r\n        <footer style=\"margin: 25px 0 20px; padding: 20px 28px; border-left: 6px solid #27ae60; background: #eef5ea; border-radius: 20px;\">\r\n            <h4 style=\"margin-top: 0; margin-bottom: 12px; color: #2c6e3c;\"><i class=\"fas fa-handshake\"></i> Sinergi Pendidikan Formal</h4>\r\n            <p style=\"margin: 0; line-height: 1.6; text-align: justify;\">\r\n                <i class=\"fas fa-building-columns\"></i> Di bawah naungan <strong>Yayasan Al Hikamussalafie</strong>, kami terus berinovasi tanpa meninggalkan tradisi. \r\n                Salah satu bentuk kontribusi nyata kami bagi masyarakat adalah pengembangan lembaga formal \r\n                <strong><i class=\"fas fa-school\"></i> SMP Nusantara Cipunagara</strong> yang berdiri pada 4 Januari 2022, serta terus mencetak generasi unggul yang berakar pada nilai-nilai pesantren.\r\n            </p>\r\n        </footer>\r\n\r\n        <!-- Komitmen Penutup -->\r\n        <div style=\"background: linear-gradient(105deg, #2f6b49, #1e543a); color: white; padding: 32px 28px; border-radius: 24px; text-align: center; margin-top: 25px;\">\r\n            <div style=\"font-size: 2rem; margin-bottom: 8px;\"><i class=\"fas fa-hands-helping\"></i></div>\r\n            <p style=\"font-size: 1rem; line-height: 1.6; margin: 0; font-weight: 500;\">\r\n                <i class=\"fas fa-star-and-crescent\"></i> Dengan berpegang pada nilai-nilai keislaman, tradisi pesantren salaf, serta semangat pendidikan, \r\n                Pondok Pesantren Al Hikamussalafie berkomitmen untuk terus mencetak generasi yang <strong><i class=\"fas fa-graduation-cap\"></i> berilmu, berakhlak mulia</strong>, \r\n                serta mampu memberikan manfaat bagi agama, masyarakat, dan bangsa. <i class=\"fas fa-star-and-crescent\"></i>\r\n            </p>\r\n        </div>\r\n\r\n        <!-- Footer informasi tambahan -->\r\n        <div style=\"margin-top: 35px; padding-top: 18px; border-top: 1px solid #e0d6c6; text-align: center; font-size: 0.7rem; color: #8b7a60; display: flex; flex-wrap: wrap; justify-content: center; gap: 24px;\">\r\n            <span><i class=\"fas fa-calendar-alt\"></i> Berdiri 1996 · Perubahan Nama 2015</span>\r\n            <span><i class=\"fas fa-building\"></i> Yayasan Al Hikamussalafie</span>\r\n            <span><i class=\"fas fa-school\"></i> SMP Nusantara Cipunagara (2022)</span>\r\n        </div>\r\n\r\n        <div style=\"text-align: center; margin-top: 30px; font-weight: 600; color: #2c5a3a; letter-spacing: 0.3px;\">\r\n            <p><i class=\"fas fa-leaf\"></i> Menuju Generasi Muslim yang Rahmatan Lil \'Alamin <i class=\"fas fa-leaf\"></i></p>\r\n        </div>\r\n    </article>\r\n</section>\r\n\r\n<!-- Font Awesome CDN untuk icon -->\r\n<link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.0.0-beta3/css/all.min.css\">', 'Publish', 'Profil', '', '1773146773_81066a13b54c9856d3d4.jpeg', NULL, 57, 0, '2024-01-21 20:36:05', '2026-01-01 20:35:00', '2026-03-24 16:06:42'),
(3, 11, 10, 'bimbingan-dan-konseling-siswa', 'Bimbingan dan Konseling Siswa', 'Bimbingan dan Konseling Siswa', '<p>Bimbingan dan Konseling Siswa</p>', 'Publish', 'Berita', '', '1773058002_64cf5fcb270a1dced014.jpg', '', 9, 0, '2024-01-21 20:38:25', '2024-01-21 20:38:00', '2026-03-10 14:40:26'),
(4, 11, 10, 'perpaduan-kurikulum-tradisional-dan-modern', 'Perpaduan Kurikulum Tradisional dan Modern', 'Pesantren ini berhasil mempertahankan tradisi Kitab Kuning (literatur klasik Islam) yang mendalam sambil tetap mengintegrasikan pendidikan formal. Hal ini memungkinkan santri untuk menguasai ilmu agama yang kokoh tanpa tertinggal dalam aspek akademik umum.', '', 'Publish', 'Keunggulan', '', '1773157101_0726895ed3d7eb969a06.jpeg', '', 0, 0, '2024-01-22 06:31:34', '2026-01-01 06:29:00', '2026-03-10 15:39:49'),
(5, 11, 10, 'sanad-keilmuan-yang-jelas', 'Sanad Keilmuan yang Jelas', 'Salah satu aspek terpenting dalam dunia pesantren adalah silsilah keilmuan (sanad). Al-Hikamussalafie memiliki garis keturunan pengajar yang tersambung dengan ulama-ulama besar, sehingga kemurnian ajaran dan keberkahan ilmu lebih terjaga.', '', 'Publish', 'Keunggulan', '', '1773157248_0e27f929f8eeabb33688.jpeg', '', 0, 0, '2024-01-22 06:34:02', '2024-01-22 06:33:00', '2026-03-10 15:40:48'),
(6, 11, 10, 'lingkungan-yang-mendukung-pembentukan-karakter', 'Lingkungan yang Mendukung Pembentukan Karakter', 'Lokasi dan sistem asramanya dirancang untuk menumbuhkan kedisiplinan dan kemandirian. Santri dilatih untuk mengatur waktu, bekerja sama dalam komunitas, dan memiliki etika (adab) yang baik terhadap guru maupun sesama.', '', 'Publish', 'Keunggulan', '', '1773157311_189d216f1ca3f11fec5b.jpeg', '', 0, 0, '2024-01-22 06:36:13', '2024-01-22 06:35:00', '2026-03-10 15:41:51'),
(7, 1, 10, 'program-praktek-kerja', 'Program Praktek Kerja', 'Sekolah ini mungkin menyelenggarakan program praktek kerja yang memungkinkan siswa untuk mendapatkan pengalaman praktis di dunia industri Java Web Media. Ini dapat membantu siswa untuk lebih siap menghadapi tantangan dunia kerja setelah lulus.', '<p>Sekolah ini mungkin menyelenggarakan program praktek kerja yang memungkinkan siswa untuk mendapatkan pengalaman praktis di dunia industri Java Web Media. Ini dapat membantu siswa untuk lebih siap menghadapi tantangan dunia kerja setelah lulus.</p>', 'Publish', 'Keunggulan', '', '1705905463_35519d31fda244428f05.png', '', 0, 0, '2024-01-22 06:37:43', '2024-01-22 06:37:00', '2024-01-22 06:37:43'),
(8, 1, 10, 'jaringan-industri-dan-alumni', 'Jaringan Industri dan Alumni', 'Keberadaan jaringan industri dan alumni yang kuat dapat memberikan manfaat besar bagi siswa. Hal ini dapat membuka peluang untuk magang, pekerjaan, atau koneksi dengan para profesional yang sudah berpengalaman di industri Java Web Media.', '<p>Keberadaan jaringan industri dan alumni yang kuat dapat memberikan manfaat besar bagi siswa. Hal ini dapat membuka peluang untuk magang, pekerjaan, atau koneksi dengan para profesional yang sudah berpengalaman di industri Java Web Media.</p>', 'Publish', 'Keunggulan', '', '1705905500_8d5df5eba3a0423168e4.png', '', 0, 0, '2024-01-22 06:38:21', '2024-01-22 06:37:00', '2024-01-22 06:38:21'),
(9, 1, 10, 'kurikulum-yang-relevan-dengan-tren-industri', 'Kurikulum yang Relevan dengan Tren Industri', 'Kurikulumnya disesuaikan dengan tren terkini dalam industri Java Web Media. Ini memastikan bahwa siswa tidak hanya mendapatkan dasar-dasar yang kuat, tetapi juga mempelajari teknologi dan konsep-konsep terbaru yang sedang berkembang.', '<p>SMK 1 Java Web Media mungkin menyesuaikan kurikulumnya dengan tren terkini dalam industri Java Web Media. Ini memastikan bahwa siswa tidak hanya mendapatkan dasar-dasar yang kuat, tetapi juga mempelajari teknologi dan konsep-konsep terbaru yang sedang berkembang.</p>', 'Publish', 'Keunggulan', '', '1705905583_bbffc68e01c3a619b451.png', '', 0, 0, '2024-01-22 06:39:43', '2024-01-22 06:39:00', '2024-01-22 06:39:43'),
(10, 1, 10, 'pengumuman-kalender-akademik-tahun-pelajaran-20242025-di-smk-1-java-web-media', 'Pengumuman Kalender Akademik Tahun Pelajaran 2024/2025 di SMK 1 Java Web Media', 'SMK 1 Java Web Media dengan gembira mengumumkan kalender akademik untuk tahun pelajaran 2024/2025. Kalender ini dirancang dengan cermat untuk memberikan panduan jelas bagi siswa, guru, dan orang tua dalam merencanakan kegiatan akademik dan non-akademik sepanjang tahun.', '<p>SMK 1 Java Web Media dengan gembira mengumumkan kalender akademik untuk tahun pelajaran 2024/2025. Kalender ini dirancang dengan cermat untuk memberikan panduan jelas bagi siswa, guru, dan orang tua dalam merencanakan kegiatan akademik dan non-akademik sepanjang tahun. Pada tanggal 10 Juli 2024, semua siswa baru diharapkan hadir untuk kegiatan orientasi, yang akan memberikan pemahaman mendalam tentang lingkungan sekolah, aturan, dan harapan untuk tahun ajaran yang akan datang.</p>\r\n<p><img src=\"http://localhost/websitesekolah/assets/upload/image/1705901868_1492c5109a950be5dac1.jpg\" alt=\"\" width=\"1080\" height=\"1080\" /></p>\r\n<p>Semester ganjil akan dimulai pada tanggal 15 Juli 2024, dan akan berlangsung hingga 15 Desember 2024. Di tengah semester, para siswa akan mengikuti ujian tengah semester untuk mengukur pemahaman mereka terhadap materi pembelajaran. Semester genap dijadwalkan dimulai pada 10 Januari 2025, dan akan berakhir pada 10 Juni 2025, dengan ujian semester sebagai penutup. Selain itu, beberapa kegiatan luar biasa seperti kegiatan ekstrakurikuler, seminar, dan acara sosial juga telah dijadwalkan untuk memperkaya pengalaman pendidikan siswa di luar kelas.</p>\r\n<p>Kami mengajak seluruh komunitas SMK 1 Java Web Media untuk memeriksa kalender akademik secara berkala, karena dapat mengalami perubahan sesuai kebutuhan sekolah. Kalender ini dapat diakses melalui situs web resmi sekolah atau dapat diperoleh di kantor administrasi. Dengan kalender akademik yang terstruktur, kami berharap dapat menciptakan lingkungan pendidikan yang terorganisir dan produktif bagi semua pihak yang terlibat.</p>', 'Publish', 'Berita', 'SMK 1 Java Web Media dengan gembira mengumumkan kalender akademik untuk tahun pelajaran 2024/2025. Kalender ini dirancang dengan cermat untuk memberikan panduan jelas bagi siswa, guru, dan orang tua dalam merencanakan kegiatan akademik dan non-akademik sepanjang tahun.', '1705911944_63893cbc4e7eb42241ca.jpg', '', 4, 0, '2024-01-22 08:25:45', '2024-01-22 08:25:00', '2024-01-22 08:35:24'),
(11, 1, 10, 'tips-sukses-menjadi-siswa-berprestasi-menyongsong-kesuksesan-pendidikan', 'Tips Sukses Menjadi Siswa Berprestasi: Menyongsong Kesuksesan Pendidikan', 'Menjadi siswa berprestasi bukanlah suatu hal yang diwariskan, tetapi merupakan hasil dari dedikasi, kerja keras, dan strategi yang tepat. Untuk membantu siswa meraih kesuksesan dalam pendidikan, berikut adalah beberapa tips yang dapat diikuti', '<p>Menjadi siswa berprestasi bukanlah suatu hal yang diwariskan, tetapi merupakan hasil dari dedikasi, kerja keras, dan strategi yang tepat. Untuk membantu siswa meraih kesuksesan dalam pendidikan, berikut adalah beberapa tips yang dapat diikuti:</p>\r\n<p>Pertama, penting bagi siswa untuk memiliki perencanaan waktu yang baik. Membuat jadwal harian dan mingguan yang terstruktur membantu siswa mengatur waktu dengan efisien, termasuk waktu untuk belajar, istirahat, dan aktivitas ekstrakurikuler. Dengan mengelola waktu dengan baik, siswa dapat meningkatkan produktivitas dan mengurangi stres.</p>\r\n<p>Kedua, siswa perlu fokus pada pemahaman konsep daripada sekadar menghafal. Mendalami materi pembelajaran dengan memahami konsep dasarnya membuat siswa lebih mampu mengaitkan informasi dan memecahkan masalah. Diskusi dengan teman sekelas dan guru juga dapat membantu memperdalam pemahaman.</p>\r\n<p>Selanjutnya, menjaga kesehatan fisik dan mental sangat penting. Aktivitas fisik yang teratur dan pola tidur yang cukup memiliki dampak positif pada konsentrasi dan daya ingat. Selain itu, berbicara tentang stres atau kesulitan belajar dengan teman, keluarga, atau guru dapat membantu mengurangi tekanan emosional dan meningkatkan kesejahteraan mental.</p>\r\n<p>Terakhir, siswa perlu memiliki sikap positif terhadap belajar dan tantangan. Melihat setiap kesalahan sebagai peluang untuk belajar, merayakan setiap pencapaian, dan memiliki tekad yang kuat untuk meraih impian pendidikan merupakan kunci keberhasilan. Dengan mengimplementasikan tips-tips ini, setiap siswa memiliki potensi untuk menjadi siswa berprestasi yang sukses dalam perjalanan pendidikannya.</p>', 'Publish', 'Berita', 'Menjadi siswa berprestasi bukanlah suatu hal yang diwariskan, tetapi merupakan hasil dari dedikasi, kerja keras, dan strategi yang tepat. Untuk membantu siswa meraih kesuksesan dalam pendidikan, berikut adalah beberapa tips yang dapat diikuti', '1705912222_1c0a6799b06d2ce50884.jpg', '', 8, 0, '2024-01-22 08:30:22', '2024-01-22 08:29:00', '2026-03-10 14:40:20'),
(12, 1, 4, 'tahun-ajaran-baru-dimulai-smk-1-java-web-media-siap-membentuk-generasi-unggul-di-bidang-teknologi', 'Tahun Ajaran Baru Dimulai: SMK 1 Java Web Media Siap Membentuk Generasi Unggul di Bidang Teknologi', 'SMK 1 Java Web Media dengan penuh semangat menyambut awal tahun ajaran baru untuk periode 2024/2025. Tahun ini, sekolah ini menargetkan memberikan pengalaman pendidikan yang lebih memukau dan relevan dalam bidang teknologi informasi, khususnya di ranah Java Web Media.', '<p>SMK 1 Java Web Media dengan penuh semangat menyambut awal tahun ajaran baru untuk periode 2024/2025. Tahun ini, sekolah ini menargetkan memberikan pengalaman pendidikan yang lebih memukau dan relevan dalam bidang teknologi informasi, khususnya di ranah Java Web Media. Pada hari pertama, 10 Juli 2024, seluruh siswa baru diberikan sambutan hangat dalam acara orientasi yang bertujuan memperkenalkan mereka dengan fasilitas sekolah, program belajar, dan nilai-nilai kebersamaan yang menjadi ciri khas SMK 1 Java Web Media.</p>\r\n<p>Sekolah ini menghadirkan kurikulum yang terkini dan inovatif, mencakup pembelajaran teknologi web terkini dan pengembangan aplikasi dengan menggunakan bahasa pemrograman Java. Dengan dukungan pengajar yang berpengalaman di industri, siswa diharapkan dapat mengembangkan keterampilan yang relevan dan sesuai dengan kebutuhan pasar kerja masa depan. SMK 1 Java Web Media juga menawarkan berbagai kegiatan ekstrakurikuler dan pelatihan keterampilan tambahan untuk memperkaya pengalaman pendidikan siswa di luar kelas.</p>\r\n<p><img src=\"http://localhost/websitesekolah/assets/upload/file/1705912588_081def33f4d490876c5a.jpg\" alt=\"\" width=\"1980\" height=\"800\" /></p>\r\n<p>Tidak hanya itu, SMK 1 Java Web Media turut memperkenalkan berbagai inisiatif baru, termasuk program mentor-mentee yang dirancang untuk memfasilitasi integrasi siswa baru dan membimbing mereka dalam menghadapi tantangan akademis dan sosial. Pihak sekolah juga berkomitmen untuk meningkatkan sarana dan prasarana, termasuk peningkatan fasilitas laboratorium komputer dan perpustakaan digital. Dengan demikian, SMK 1 Java Web Media bertekad menciptakan lingkungan belajar yang inspiratif dan mendukung bagi setiap siswa agar dapat mencapai potensi maksimalnya.</p>', 'Publish', 'Berita', 'SMK 1 Java Web Media dengan penuh semangat menyambut awal tahun ajaran baru untuk periode 2024/2025. Tahun ini, sekolah ini menargetkan memberikan pengalaman pendidikan yang lebih memukau dan relevan dalam bidang teknologi informasi, khususnya di ranah Java Web Media.', '1705912322_34042eaa2dd025a6b96d.jpg', '', 15, 0, '2024-01-22 08:32:02', '2024-01-22 08:31:00', '2026-03-10 14:40:17'),
(17, 11, 10, 'sejarah-smp-nusantara-cipunagara', 'SEJARAH SMP NUSANTARA CIPUNAGARA', 'Sejarah Smp Nusantara Cipunagara', '<section id=\"sejarah-smp\" style=\"max-width: 1100px; margin: 30px auto; font-family: \'Segoe UI\', \'Poppins\', system-ui, -apple-system, sans-serif; background: #ffffff; border-radius: 28px; box-shadow: 0 20px 40px rgba(0,0,0,0.05); overflow: hidden;\">\r\n    \r\n    <!-- Header dengan latar gradien biru kehijauan -->\r\n    <header style=\"background: linear-gradient(135deg, #2c6e9e, #1a4d6b); padding: 45px 30px 40px; text-align: center; color: white;\">\r\n        <div style=\"font-size: 48px; margin-bottom: 15px;\">\r\n            <i class=\"fas fa-school\" style=\"background: rgba(255,255,255,0.15); padding: 12px 20px; border-radius: 60px;\"></i>\r\n        </div>\r\n        <h1 style=\"font-size: 2.2rem; margin: 0 0 12px 0; font-weight: 700; letter-spacing: -0.5px;\">\r\n            SMP Nusantara Cipunagara\r\n        </h1>\r\n        <p style=\"font-size: 0.95rem; opacity: 0.9; margin: 0; border-top: 1px solid rgba(255,255,255,0.3); display: inline-block; padding-top: 12px;\">\r\n            <i class=\"fas fa-quote-left\"></i> \"Mendidik Generasi Berkarakter, Berprestasi, dan Berakhlak Mulia\" <i class=\"fas fa-quote-right\"></i>\r\n        </p>\r\n    </header>\r\n\r\n    <!-- Badge info singkat -->\r\n    <div style=\"display: flex; flex-wrap: wrap; gap: 16px; background: #f0f7fc; padding: 18px 28px; border-bottom: 1px solid #d4e3ed;\">\r\n        <div style=\"display: flex; align-items: center; gap: 10px;\">\r\n            <span style=\"background: #2c6e9e; width: 32px; height: 32px; display: inline-flex; align-items: center; justify-content: center; border-radius: 50%; color: white;\"><i class=\"fas fa-calendar-alt\"></i></span>\r\n            <span><strong style=\"color: #1a5d7a;\">KBM Dimulai:</strong> 4 Januari 2022</span>\r\n        </div>\r\n        <div style=\"display: flex; align-items: center; gap: 10px;\">\r\n            <span style=\"background: #2c6e9e; width: 32px; height: 32px; display: inline-flex; align-items: center; justify-content: center; border-radius: 50%; color: white;\"><i class=\"fas fa-user-tie\"></i></span>\r\n            <span><strong style=\"color: #1a5d7a;\">Kepala Sekolah:</strong> Hamdan Hidayat, S.H.</span>\r\n        </div>\r\n        <div style=\"display: flex; align-items: center; gap: 10px;\">\r\n            <span style=\"background: #2c6e9e; width: 32px; height: 32px; display: inline-flex; align-items: center; justify-content: center; border-radius: 50%; color: white;\"><i class=\"fas fa-building\"></i></span>\r\n            <span><strong style=\"color: #1a5d7a;\">Yayasan:</strong> Al Hikamussalafie</span>\r\n        </div>\r\n    </div>\r\n\r\n    <!-- Konten Sejarah Utama -->\r\n    <article style=\"padding: 35px 32px; line-height: 1.85; color: #2c3e2f; background: #ffffff;\">\r\n        \r\n        <!-- Timeline Sejarah -->\r\n        <div style=\"position: relative; margin-bottom: 35px;\">\r\n            <!-- Garis Timeline -->\r\n            <div style=\"position: absolute; left: 30px; top: 20px; bottom: 20px; width: 3px; background: linear-gradient(180deg, #2c6e9e, #e6bc7e); border-radius: 3px;\"></div>\r\n            \r\n            <!-- Point 1: Perubahan Nama Pesantren -->\r\n            <div style=\"display: flex; gap: 20px; margin-bottom: 35px; position: relative;\">\r\n                <div style=\"width: 60px; height: 60px; background: #e8f0f5; border-radius: 50%; display: flex; align-items: center; justify-content: center; border: 3px solid #2c6e9e; z-index: 1; background: white;\">\r\n                    <i class=\"fas fa-exchange-alt\" style=\"color: #2c6e9e; font-size: 1.3rem;\"></i>\r\n                </div>\r\n                <div style=\"flex: 1;\">\r\n                    <div style=\"display: flex; flex-wrap: wrap; gap: 10px; align-items: center; margin-bottom: 8px;\">\r\n                        <span style=\"background: #2c6e9e; color: white; padding: 4px 14px; border-radius: 30px; font-size: 0.75rem; font-weight: 600;\">\r\n                            <i class=\"fas fa-calendar-alt\"></i> 10 Januari 2015 M\r\n                        </span>\r\n                        <span style=\"background: #e6bc7e; color: #2c3e2f; padding: 4px 14px; border-radius: 30px; font-size: 0.75rem; font-weight: 600;\">\r\n                            <i class=\"fas fa-moon\"></i> 19 Rabiul Awal 1436 H\r\n                        </span>\r\n                    </div>\r\n                    <h3 style=\"margin: 0 0 10px 0; color: #2c6e9e; font-size: 1.25rem;\">\r\n                        <i class=\"fas fa-mosque\"></i> Perubahan Nama Pesantren\r\n                    </h3>\r\n                    <p style=\"margin: 0; text-align: justify; color: #4a5b6e;\">\r\n                        Pergantian nama dari <strong>Pondok Pesantren Syarif Hidayatullah</strong> menjadi \r\n                        <strong>Pondok Pesantren Al Hikamussalafie</strong>. Momen bersejarah ini menjadi titik awal \r\n                        transformasi lembaga pendidikan Islam di wilayah Cipunagara.\r\n                    </p>\r\n                </div>\r\n            </div>\r\n\r\n            <!-- Point 2: Masa Sulit -->\r\n            <div style=\"display: flex; gap: 20px; margin-bottom: 35px; position: relative;\">\r\n                <div style=\"width: 60px; height: 60px; background: #e8f0f5; border-radius: 50%; display: flex; align-items: center; justify-content: center; border: 3px solid #e6bc7e; z-index: 1; background: white;\">\r\n                    <i class=\"fas fa-frown\" style=\"color: #e6bc7e; font-size: 1.3rem;\"></i>\r\n                </div>\r\n                <div style=\"flex: 1;\">\r\n                    <div style=\"margin-bottom: 8px;\">\r\n                        <span style=\"background: #e6bc7e; color: #2c3e2f; padding: 4px 14px; border-radius: 30px; font-size: 0.75rem; font-weight: 600;\">\r\n                            <i class=\"fas fa-clock\"></i> 2015 - 2021\r\n                        </span>\r\n                    </div>\r\n                    <h3 style=\"margin: 0 0 10px 0; color: #e6bc7e; font-size: 1.25rem;\">\r\n                        <i class=\"fas fa-users-slash\"></i> Masa Sulit: Minimnya Pendaftar\r\n                    </h3>\r\n                    <p style=\"margin: 0; text-align: justify; color: #4a5b6e;\">\r\n                        Sejak perubahan nama pesantren, tidak ada anak santri yang mendaftar ke pondok pesantren \r\n                        kecuali hanya anak dari <strong>Kampung Tanjung Sari</strong> atau kampung sendiri. \r\n                        Hal ini dikarenakan setiap ada wali murid yang bertanya tentang <strong>sekolah formal</strong>, \r\n                        karena belum ada sekolah maka tidak ada yang mau mendaftar di pesantren.\r\n                    </p>\r\n                </div>\r\n            </div>\r\n\r\n            <!-- Point 3: Gagasan & Izin -->\r\n            <div style=\"display: flex; gap: 20px; margin-bottom: 35px; position: relative;\">\r\n                <div style=\"width: 60px; height: 60px; background: #e8f0f5; border-radius: 50%; display: flex; align-items: center; justify-content: center; border: 3px solid #2c6e9e; z-index: 1; background: white;\">\r\n                    <i class=\"fas fa-lightbulb\" style=\"color: #2c6e9e; font-size: 1.3rem;\"></i>\r\n                </div>\r\n                <div style=\"flex: 1;\">\r\n                    <div style=\"margin-bottom: 8px;\">\r\n                        <span style=\"background: #2c6e9e; color: white; padding: 4px 14px; border-radius: 30px; font-size: 0.75rem; font-weight: 600;\">\r\n                            <i class=\"fas fa-calendar-week\"></i> Januari 2022\r\n                        </span>\r\n                    </div>\r\n                    <h3 style=\"margin: 0 0 10px 0; color: #2c6e9e; font-size: 1.25rem;\">\r\n                        <i class=\"fas fa-handshake\"></i> Gagasan & Perizinan\r\n                    </h3>\r\n                    <p style=\"margin: 0; text-align: justify; color: #4a5b6e;\">\r\n                        Di tahun 2022 Januari dimulainya gagasan mendirikan sekolah SMP dan disepakati dari semua pihak, \r\n                        baik dari pesantren maupun dari warga setempat. Kemudian dibuat surat izin lingkungan hingga mendapat \r\n                        izin dari lingkungan setempat dan dari sekolah lain, di antaranya ada izin dari \r\n                        <strong>SMPN Cipunagara</strong>.\r\n                    </p>\r\n                </div>\r\n            </div>\r\n\r\n            <!-- Point 4: KBM Dimulai -->\r\n            <div style=\"display: flex; gap: 20px; margin-bottom: 35px; position: relative;\">\r\n                <div style=\"width: 60px; height: 60px; background: #e8f0f5; border-radius: 50%; display: flex; align-items: center; justify-content: center; border: 3px solid #27ae60; z-index: 1; background: white;\">\r\n                    <i class=\"fas fa-flag-checkered\" style=\"color: #27ae60; font-size: 1.3rem;\"></i>\r\n                </div>\r\n                <div style=\"flex: 1;\">\r\n                    <div style=\"margin-bottom: 8px;\">\r\n                        <span style=\"background: #27ae60; color: white; padding: 4px 14px; border-radius: 30px; font-size: 0.75rem; font-weight: 600;\">\r\n                            <i class=\"fas fa-calendar-check\"></i> 4 Januari 2022\r\n                        </span>\r\n                    </div>\r\n                    <h3 style=\"margin: 0 0 10px 0; color: #27ae60; font-size: 1.25rem;\">\r\n                        <i class=\"fas fa-school\"></i> Kegiatan Belajar Mengajar Dimulai\r\n                    </h3>\r\n                    <p style=\"margin: 0; text-align: justify; color: #4a5b6e;\">\r\n                        <strong>Sekolah Menengah Pertama (SMP) Nusantara Cipunagara</strong> resmi memulai \r\n                        kegiatan belajar mengajar (KBM). Hari pertama ini menjadi babak baru bagi pendidikan \r\n                        formal di lingkungan pesantren, menjawab kebutuhan masyarakat akan sekolah yang \r\n                        berbasis nilai-nilai Islam.\r\n                    </p>\r\n                </div>\r\n            </div>\r\n\r\n            <!-- Point 5: Kepala Sekolah Pertama -->\r\n            <div style=\"display: flex; gap: 20px; position: relative;\">\r\n                <div style=\"width: 60px; height: 60px; background: #e8f0f5; border-radius: 50%; display: flex; align-items: center; justify-content: center; border: 3px solid #e6bc7e; z-index: 1; background: white;\">\r\n                    <i class=\"fas fa-user-tie\" style=\"color: #e6bc7e; font-size: 1.3rem;\"></i>\r\n                </div>\r\n                <div style=\"flex: 1;\">\r\n                    <div style=\"margin-bottom: 8px;\">\r\n                        <span style=\"background: #e6bc7e; color: #2c3e2f; padding: 4px 14px; border-radius: 30px; font-size: 0.75rem; font-weight: 600;\">\r\n                            <i class=\"fas fa-scroll\"></i> Rabu, 1 Juni 2022\r\n                        </span>\r\n                    </div>\r\n                    <h3 style=\"margin: 0 0 10px 0; color: #e6bc7e; font-size: 1.25rem;\">\r\n                        <i class=\"fas fa-crown\"></i> Kepala Sekolah Pertama Ditetapkan\r\n                    </h3>\r\n                    <p style=\"margin: 0; text-align: justify; color: #4a5b6e;\">\r\n                        <strong>Bpk Hamdan Hidayat, S.H.</strong> diangkat sebagai kepala sekolah pertama \r\n                        SMP Nusantara Cipunagara atas <strong>SK Yayasan Al Hikamussalafie</strong>. \r\n                        Penetapan ini menjadi tonggak kepemimpinan yang membawa visi sekolah menuju \r\n                        pendidikan berkualitas dengan pondasi nilai-nilai pesantren.\r\n                    </p>\r\n                </div>\r\n            </div>\r\n        </div>\r\n\r\n        <!-- Card Info Kepala Sekolah -->\r\n        <div style=\"background: linear-gradient(115deg, #f0f7fc, #e8f0f5); border-radius: 24px; padding: 25px; margin: 30px 0; text-align: center;\">\r\n            <div style=\"display: flex; flex-direction: column; align-items: center;\">\r\n                <div style=\"background: #2c6e9e; width: 80px; height: 80px; border-radius: 50%; display: flex; align-items: center; justify-content: center; margin-bottom: 15px;\">\r\n                    <i class=\"fas fa-chalkboard-user\" style=\"font-size: 2.5rem; color: white;\"></i>\r\n                </div>\r\n                <h3 style=\"margin: 0 0 5px 0; color: #1a5d7a; font-size: 1.3rem;\">Hamdan Hidayat, S.H.</h3>\r\n                <p style=\"margin: 0 0 5px 0; color: #4a5b6e;\"><i class=\"fas fa-trophy\"></i> Kepala Sekolah Pertama</p>\r\n                <p style=\"margin: 0; font-size: 0.85rem; color: #6c7a8a;\">\r\n                    <i class=\"fas fa-calendar-alt\"></i> SK Yayasan Al Hikamussalafie | 1 Juni 2022\r\n                </p>\r\n            </div>\r\n        </div>\r\n\r\n        <!-- Visi Misi Singkat -->\r\n        <div style=\"background: #fef9ef; border-radius: 20px; padding: 22px 25px; margin: 25px 0; border-left: 5px solid #e6bc7e;\">\r\n            <h4 style=\"margin: 0 0 12px 0; color: #2c6e9e; display: flex; align-items: center; gap: 10px;\">\r\n                <i class=\"fas fa-bullseye\"></i> Komitmen SMP Nusantara Cipunagara\r\n            </h4>\r\n            <p style=\"margin: 0; text-align: justify; line-height: 1.7;\">\r\n                Berdiri sebagai jawaban atas kebutuhan pendidikan formal yang terintegrasi dengan nilai-nilai pesantren, \r\n                <strong>SMP Nusantara Cipunagara</strong> berkomitmen mencetak generasi yang <strong>unggul dalam ilmu pengetahuan, \r\n                kokoh dalam iman dan takwa, serta berakhlak mulia</strong>. Dengan sinergi antara pesantren dan sekolah, \r\n                kami hadir untuk memberikan pendidikan terbaik bagi masyarakat Cipunagara dan sekitarnya.\r\n            </p>\r\n        </div>\r\n\r\n        <!-- Footer Informasi -->\r\n        <div style=\"margin-top: 30px; padding-top: 20px; border-top: 1px solid #e0e6e8; text-align: center; font-size: 0.7rem; color: #8b9aae; display: flex; flex-wrap: wrap; justify-content: center; gap: 24px;\">\r\n            <span><i class=\"fas fa-calendar-alt\"></i> KBM Dimulai: 4 Januari 2022</span>\r\n            <span><i class=\"fas fa-user-check\"></i> Kepala Sekolah: Hamdan Hidayat, S.H. (1 Juni 2022)</span>\r\n            <span><i class=\"fas fa-building\"></i> Yayasan Al Hikamussalafie</span>\r\n        </div>\r\n\r\n        <div style=\"text-align: center; margin-top: 25px; font-weight: 600; color: #2c6e9e; letter-spacing: 0.3px;\">\r\n            <p><i class=\"fas fa-leaf\"></i> Membangun Generasi Berkarakter, Berprestasi, dan Berakhlak Mulia <i class=\"fas fa-leaf\"></i></p>\r\n        </div>\r\n    </article>\r\n</section>\r\n\r\n<!-- Font Awesome CDN untuk icon -->\r\n<link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.0.0-beta3/css/all.min.css\">', 'Publish', 'Profil', '', '1774364997_e71a7fcebe4e3c01c248.jpeg', NULL, 11, 0, '2026-03-24 15:09:57', '2026-03-24 15:07:00', '2026-03-24 16:06:47');
