INSERT INTO `ekstrakurikuler` (`id_ekstrakurikuler`, `id_kategori_ekstrakurikuler`, `id_user`, `slug_ekstrakurikuler`, `judul_ekstrakurikuler`, `nama_penanggung_jawab`, `isi`, `gambar`, `website`, `text_website`, `hits`, `status_text`, `status_ekstrakurikuler`, `tanggal_post`, `tanggal`) VALUES
(5, 7, 1, 'ektrakurikuler-bahasa-inggris', 'Ekstrakurikuler Bahasa Inggris', 'Iqra Rayyan Andoyo', '<p>Ekstrakurikuler Bahasa Inggris di sekolah memberikan siswa kesempatan yang berharga untuk memperdalam pemahaman dan keterampilan mereka dalam bahasa internasional yang sangat penting ini. Melalui kegiatan seperti permainan bahasa, perdebatan, drama, dan pembacaan, siswa dapat meningkatkan kemampuan mereka dalam berbicara, mendengarkan, membaca, dan menulis bahasa Inggris. Ini tidak hanya membantu mereka dalam lingkungan akademis, tetapi juga mempersiapkan mereka untuk sukses dalam karier masa depan yang semakin global.</p>\r\n<p>Dalam ekstrakurikuler Bahasa Inggris, siswa memiliki kesempatan untuk terlibat dalam proyek-proyek kreatif yang memungkinkan mereka untuk mengekspresikan diri dalam bahasa Inggris. Mereka dapat menulis cerita, puisi, esai, atau bahkan membuat film pendek dalam bahasa Inggris, yang membantu mereka mengasah keterampilan bahasa sambil mengekspresikan ide dan perasaan mereka dengan cara yang berbeda. Aktivitas-aktivitas ini juga memperluas wawasan budaya siswa karena mereka belajar tentang berbagai aspek budaya yang terkait dengan bahasa Inggris di seluruh dunia.</p>\r\n<p>Selain itu, ekstrakurikuler Bahasa Inggris juga sering kali mencakup persiapan untuk ujian kemampuan berbahasa seperti TOEFL atau IELTS. Dengan bimbingan guru yang berpengalaman, siswa dapat mengembangkan strategi dan keterampilan yang diperlukan untuk berhasil dalam ujian tersebut. Hal ini membuka pintu bagi mereka untuk mengejar studi lanjutan di luar negeri atau mencari pekerjaan di perusahaan multinasional di masa depan. Dengan demikian, ekstrakurikuler Bahasa Inggris tidak hanya membantu siswa untuk menjadi lebih mahir dalam bahasa, tetapi juga membuka peluang-peluang baru dan menantang bagi masa depan mereka.</p>', '1706444023_e9f12f5b3739f7825d92.jpg', '', '', 2, 'Ya', 'Publish', '2024-01-21 10:07:06', '2024-01-21 10:07:06'),
(6, 6, 1, 'pencak-silat-tapak-suci', 'Ekstrakurikuler Pencak Silat - Tapak Suci', 'Andoyo', '<p>Pencak Silat, sebagai salah satu ekstrakurikuler yang diminati di sekolah, menawarkan siswa pengalaman yang mendalam dalam seni bela diri tradisional Indonesia. Dalam kegiatan ini, siswa diajak untuk mempelajari teknik-teknik bertahan, menyerang, dan menghindar yang berkembang dari berbagai budaya dan tradisi di Nusantara. Melalui latihan intensif, siswa tidak hanya meningkatkan kebugaran fisik mereka, tetapi juga memperdalam pemahaman mereka akan kedisiplinan, konsentrasi, dan pengendalian diri. Selain itu, Pencak Silat juga membuka jendela bagi siswa untuk memahami nilai-nilai budaya dan warisan sejarah Indonesia yang kaya.</p>\r\n<p>Dalam ekstrakurikuler Pencak Silat, siswa tidak hanya diajarkan gerakan-gerakan dasar dan teknik bertarung, tetapi juga dibimbing untuk memahami filosofi di balik setiap gerakan. Mereka belajar tentang pentingnya keselarasan antara tubuh, pikiran, dan jiwa dalam seni bela diri ini. Selain itu, latihan bersama dengan instruktur yang berpengalaman juga membantu siswa membangun rasa persaudaraan dan kerjasama tim, karena Pencak Silat tidak hanya tentang keterampilan individu, tetapi juga tentang bagaimana mereka berinteraksi dan bekerja sama dalam kelompok.</p>\r\n<p>Selain manfaat fisik dan mental, ekstrakurikuler Pencak Silat juga memberikan kesempatan kepada siswa untuk berpartisipasi dalam kompetisi dan pertunjukan. Mereka dapat mengasah keterampilan mereka dalam konteks yang lebih kompetitif atau menggali kreativitas mereka dalam pertunjukan seni bela diri. Melalui pengalaman ini, siswa belajar tentang sportivitas, keberanian, dan rasa percaya diri saat mereka mengeksplorasi potensi mereka dalam sebuah arena yang lebih luas. Dengan demikian, ekstrakurikuler Pencak Silat tidak hanya memberikan kesempatan bagi siswa untuk berkembang secara fisik dan mental, tetapi juga memperkaya pengalaman mereka dalam merayakan warisan budaya Indonesia yang kaya.</p>', '1706443915_cfcdf82cf5049ed74f25.jpg', '', '', 4, 'Ya', 'Publish', '2024-01-21 12:32:06', '2024-01-21 12:32:06'),
(7, 6, 1, 'ekstrakurikuler-sepak-bola-dan-futsal', 'Ekstrakurikuler Sepak Bola dan Futsal', 'Izra Rashid Andoyo', '<p>Ekstrakurikuler sepak bola dan futsal di sekolah merupakan platform yang sangat efektif untuk mengembangkan keterampilan atletik, kerja tim, dan semangat kompetitif siswa. Melalui latihan rutin dan pertandingan, siswa memiliki kesempatan untuk meningkatkan teknik dasar seperti dribbling, passing, shooting, dan strategi permainan yang diperlukan dalam sepak bola dan futsal. Aktivitas ini juga membantu meningkatkan kebugaran fisik dan kesehatan secara keseluruhan, sambil mempromosikan gaya hidup aktif di antara siswa.</p>\r\n<p>Selain itu, ekstrakurikuler sepak bola dan futsal juga memperkuat rasa persaudaraan dan kerjasama tim di antara pesertanya. Siswa belajar untuk saling mendukung, berkomunikasi, dan bekerja sama untuk mencapai tujuan bersama dalam pertandingan. Ini membentuk keterampilan interpersonal yang penting dalam kehidupan sehari-hari, baik di sekolah maupun di luar sekolah, serta mengajarkan nilai-nilai penting seperti sportivitas, kejujuran, dan rasa tanggung jawab.</p>\r\n<p>Selain itu, ekstrakurikuler sepak bola dan futsal sering kali menjadi wadah untuk mengasah bakat dan potensi atletis siswa. Mereka yang menonjol dalam olahraga ini dapat diberi kesempatan untuk berpartisipasi dalam kompetisi antar-sekolah, turnamen regional, atau bahkan mendapatkan beasiswa olahraga di tingkat universitas. Dengan demikian, ekstrakurikuler sepak bola dan futsal bukan hanya tentang mengembangkan keterampilan olahraga, tetapi juga membuka pintu untuk pengakuan, prestasi, dan kesempatan berprestasi bagi para siswa yang berbakat dalam dunia olahraga.</p>', '1706444186_14c5cddd1fec87bec076.jpg', '', '', NULL, 'Ya', 'Publish', '2024-01-28 12:16:26', '2024-01-28 12:16:26'),
(8, 6, 1, 'ekstrakurikuler-bola-basket', 'Ekstrakurikuler Bola Basket', 'Kheira Alexandrina Andoyo', '<p>Ekstrakurikuler bola basket di sekolah tidak hanya merupakan kesempatan bagi siswa untuk mengasah keterampilan olahraga, tetapi juga untuk membangun karakter dan kepemimpinan. Melalui latihan yang terstruktur dan permainan yang intens, siswa dapat memperbaiki teknik dasar seperti dribbling, passing, shooting, dan defensive skills yang penting dalam bola basket. Selain itu, mereka juga belajar tentang strategi permainan, pemahaman posisi, dan taktik tim yang diperlukan untuk berhasil dalam kompetisi.</p>\r\n<p>Salah satu aspek paling berharga dari ekstrakurikuler bola basket adalah kemampuannya untuk mengajarkan siswa tentang kerja tim dan rasa tanggung jawab. Dalam tim bola basket, siswa belajar untuk saling mendukung, berkomunikasi, dan menghargai peran masing-masing anggota tim. Mereka juga belajar mengatasi tantangan bersama dan merayakan kesuksesan bersama, membangun rasa persaudaraan yang kuat di antara sesama pemain.</p>\r\n<p>Selain aspek fisik dan sosial, ekstrakurikuler bola basket juga menawarkan kesempatan bagi siswa untuk mengembangkan kepemimpinan dan keterampilan organisasional. Siswa yang menonjol dapat dipercaya untuk memimpin tim, mengoordinasikan latihan, atau bahkan menjadi pelatih asisten. Ini tidak hanya memperkuat keterampilan kepemimpinan mereka, tetapi juga memberikan pengalaman praktis yang berharga dalam manajemen waktu, pengambilan keputusan, dan pemecahan masalah. Dengan demikian, ekstrakurikuler bola basket bukan hanya tentang olahraga, tetapi juga tentang membangun karakter, kepemimpinan, dan keterampilan hidup yang diperlukan untuk kesuksesan di luar lapangan.</p>', '1706444251_1c8744ea0e62b916510d.jpg', '', '', NULL, 'Ya', 'Publish', '2024-01-28 12:17:31', '2024-01-28 12:17:31'),
(9, 7, 1, 'ekstrakurikuler-menulis-fiksi-dan-ilmiah', 'Ekstrakurikuler Menulis Fiksi dan Ilmiah', 'Kinara Almadina Andoyo', '<p>Ekstrakurikuler menulis fiksi dan ilmiah di sekolah membuka pintu bagi siswa untuk mengeksplorasi imajinasi mereka dan mengembangkan keterampilan menulis yang kuat. Dalam kegiatan ini, siswa diajak untuk merancang cerita-cerita fiksi yang unik, menggali karakter, dan membangun alur yang menarik. Mereka belajar tentang elemen-elemen naratif seperti plot, karakterisasi, setting, dan tema, serta menerapkan teknik-teknik penulisan kreatif untuk menghasilkan karya yang orisinal dan bermakna.</p>\r\n<p>Selain fiksi, ekstrakurikuler menulis ilmiah juga memberikan kesempatan bagi siswa untuk mempelajari dan mengeksplorasi topik-topik yang relevan dalam ilmu pengetahuan dan teknologi. Siswa diajak untuk menyusun laporan penelitian, artikel ilmiah, atau esai analitis yang mendalam tentang berbagai topik, mulai dari biologi hingga astronomi. Mereka belajar tentang struktur dan format penulisan ilmiah, pentingnya penelitian yang terperinci, serta bagaimana menyajikan data dan fakta secara jelas dan akurat.</p>\r\n<p>Melalui ekstrakurikuler menulis fiksi dan ilmiah, siswa juga mengembangkan keterampilan berpikir kritis, analitis, dan kreatif. Mereka diajak untuk mempertimbangkan berbagai sudut pandang, merumuskan argumen yang kuat, dan menyampaikan ide-ide mereka secara efektif dalam bentuk tulisan. Aktivitas ini tidak hanya membantu meningkatkan kemampuan komunikasi tertulis siswa, tetapi juga membuka jalan bagi mereka untuk mengeksplorasi minat mereka secara lebih mendalam dan mengejar karier di bidang penulisan, jurnalisme, atau ilmu pengetahuan. Dengan demikian, ekstrakurikuler menulis fiksi dan ilmiah tidak hanya memberikan kesenangan dan kreativitas, tetapi juga memberdayakan siswa untuk menjadi penulis yang terampil dan berpikiran tajam.</p>', '1706444345_043ca1907b1e66fe2b77.jpg', '', '', NULL, 'Ya', 'Publish', '2024-01-28 12:19:05', '2024-01-28 12:19:05'),
(10, 7, 1, 'ekstrakurikuler-pencinta-alam-dan-lingkungan', 'Ekstrakurikuler Pencinta Alam dan Lingkungan', 'Aria Nurdiana', '<p>Ekstrakurikuler Pencinta Alam dan Lingkungan di sekolah menjadi wahana yang menarik bagi siswa untuk mengeksplorasi keindahan alam sekitar dan memperdalam pemahaman mereka tentang pentingnya pelestarian lingkungan. Melalui kegiatan seperti hiking, camping, dan eksplorasi alam, siswa diajak untuk menjelajahi keanekaragaman hayati dan keindahan alam di sekitar mereka. Mereka belajar tentang ekosistem, perlindungan satwa liar, serta upaya-upaya yang dapat dilakukan untuk mengurangi dampak negatif terhadap lingkungan.</p>\r\n<p>Dalam ekstrakurikuler ini, siswa juga terlibat dalam proyek-proyek pelestarian lingkungan yang bertujuan untuk meningkatkan kesadaran dan tanggung jawab mereka terhadap lingkungan. Mereka bisa terlibat dalam kegiatan seperti penanaman pohon, pembersihan pantai, daur ulang, dan kampanye lingkungan. Ini memberikan kesempatan bagi siswa untuk berkontribusi secara positif terhadap komunitas mereka dan merasakan dampak nyata dari tindakan-tindakan kecil yang dapat dilakukan untuk menjaga kelestarian lingkungan.</p>\r\n<p>Selain itu, ekstrakurikuler Pencinta Alam dan Lingkungan juga menjadi sumber inspirasi untuk siswa dalam mengembangkan kesadaran akan isu-isu lingkungan global. Mereka belajar tentang perubahan iklim, polusi, dan kerusakan lingkungan lainnya yang menjadi tantangan besar di era modern ini. Melalui diskusi, seminar, dan kegiatan edukatif lainnya, siswa dapat merangsang pikiran mereka sendiri dan bertindak sebagai agen perubahan yang peduli terhadap masa depan planet kita. Dengan demikian, ekstrakurikuler ini tidak hanya membentuk hubungan yang lebih dalam antara siswa dan alam, tetapi juga membantu membentuk generasi yang bertanggung jawab dan sadar lingkungan.</p>', '1706444422_496e8cbb46698d7427e3.jpg', '', '', 1, 'Ya', 'Publish', '2024-01-28 12:20:23', '2024-01-28 12:20:23'),
(11, 5, 1, 'ekstrakurikuler-desain-grafis-dan-programming', 'Ekstrakurikuler Desain Grafis dan Programming', 'Eflita Meiyetriani', '<p>Ekstrakurikuler Desain Grafis dan Programming di sekolah menjadi jendela bagi siswa untuk mempelajari keterampilan kreatif dan teknis yang mendasar dalam dunia teknologi informasi. Dalam kegiatan ini, siswa diperkenalkan pada konsep desain grafis yang meliputi penggunaan perangkat lunak desain seperti Adobe Photoshop, Illustrator, atau CorelDRAW. Mereka belajar tentang prinsip-prinsip desain, pemilihan warna, tipografi, dan pengaturan komposisi untuk menciptakan karya-karya visual yang menarik dan berarti.</p>\r\n<p>Sementara itu, dalam ekstrakurikuler Programming, siswa diperkenalkan pada dasar-dasar pemrograman komputer menggunakan bahasa pemrograman seperti Python, Java, atau HTML/CSS. Mereka belajar tentang algoritma, struktur data, logika pemrograman, dan pengembangan aplikasi sederhana. Aktivitas ini membantu siswa memahami konsep-konsep yang mendasari teknologi informasi dan memperluas pemahaman mereka tentang cara kerja aplikasi dan program komputer.</p>\r\n<p>Kombinasi ekstrakurikuler Desain Grafis dan Programming memungkinkan siswa untuk menggabungkan kreativitas dengan keahlian teknis, membuka peluang untuk eksplorasi karier di bidang desain web, pengembangan perangkat lunak, atau industri kreatif lainnya. Selain itu, mereka juga dapat belajar tentang pentingnya desain yang responsif dan interaktif dalam pengalaman pengguna digital yang modern. Dengan demikian, ekstrakurikuler ini tidak hanya membantu siswa mengembangkan keterampilan praktis yang berguna, tetapi juga mempersiapkan mereka untuk menjadi inovator dan pemimpin dalam dunia teknologi yang terus berkembang pesat.</p>', '1706444520_576786674d578e98ae0d.jpg', '', '', NULL, 'Ya', 'Publish', '2024-01-28 12:22:01', '2024-01-28 12:22:01'),
