INSERT INTO `gelombang` (`id_gelombang`, `id_user`, `tahun_ajaran`, `tahap`, `tahun`, `slug`, `judul`, `isi`, `tanggal_buka`, `tanggal_tutup`, `tanggal_pengumuman`, `status_gelombang`, `gambar`, `tanggal`) VALUES
(1, 11, '2026/2027', 1, '2026', 'ppdb-tahap-1-tahun-ajaran-20262027', 'PPDB Tahap 1 - Tahun Ajaran 2026/2027', '<p><strong>Penerimaan Peserta Didik Baru (PPDB) HAQI Learning Center Tahun Ajaran 2026/2027</strong></p>\r\n<p>HAQI Learning Center membuka kesempatan bagi calon peserta didik baru untuk bergabung dalam lingkungan pendidikan berkualitas yang berorientasi pada pengembangan akademik dan karakter. Berikut adalah informasi mengenai proses Penerimaan Peserta Didik Baru (PPDB) Tahun Ajaran 2026/2027.</p>\r\n<h2><strong>Tahapan Pendaftaran</strong></h2>\r\n<h3>1. <strong>Pendaftaran Online</strong></h3>\r\n<p>Calon peserta didik harus melakukan pendaftaran secara online melalui website resmi HAQI Learning Center di [website resmi].</p>\r\n<ul>\r\n<li>Mengisi formulir pendaftaran dengan lengkap dan benar.</li>\r\n<li>Mengunggah dokumen persyaratan yang telah ditentukan.</li>\r\n<li>Menerima kode pendaftaran sebagai bukti pendaftaran.</li>\r\n</ul>\r\n<h3>2. <strong>Verifikasi Dokumen</strong></h3>\r\n<p>Tim administrasi akan melakukan verifikasi dokumen yang telah diunggah. Jika terdapat kekurangan, calon peserta didik akan diinformasikan untuk melengkapi dokumen dalam batas waktu yang telah ditentukan.</p>\r\n<h3>3. <strong>Tes Seleksi</strong></h3>\r\n<p>Calon peserta didik yang telah lolos tahap verifikasi dokumen akan mengikuti tes seleksi akademik dan wawancara. Tes seleksi mencakup:</p>\r\n<ul>\r\n<li>Tes akademik sesuai jenjang pendidikan.</li>\r\n<li>Wawancara calon peserta didik dan orang tua/wali.</li>\r\n</ul>\r\n<h3>4. <strong>Pengumuman Hasil Seleksi</strong></h3>\r\n<p>Hasil seleksi akan diumumkan melalui website resmi dan email yang telah didaftarkan.</p>\r\n<h3>5. <strong>Registrasi Ulang</strong></h3>\r\n<p>Peserta yang lolos seleksi harus melakukan registrasi ulang dengan:</p>\r\n<ul>\r\n<li>Membayar biaya pendidikan sesuai ketentuan.</li>\r\n<li>Mengumpulkan dokumen fisik ke kantor administrasi HAQI Learning Center.</li>\r\n<li>Mengikuti sesi orientasi bagi peserta didik baru.</li>\r\n</ul>\r\n<h2><strong>Persyaratan Dokumen</strong></h2>\r\n<p>Untuk mengikuti PPDB HAQI Learning Center Tahun Ajaran 2026/2027, calon peserta didik wajib melampirkan dokumen sebagai berikut:</p>\r\n<ol>\r\n<li><strong>Dokumen Umum:</strong>\r\n<ul>\r\n<li>Formulir pendaftaran yang telah diisi dan ditandatangani.</li>\r\n<li>Fotokopi Akta Kelahiran.</li>\r\n<li>Fotokopi Kartu Keluarga.</li>\r\n<li>Fotokopi KTP orang tua/wali.</li>\r\n<li>Pas foto berwarna ukuran 3x4 (3 lembar).</li>\r\n</ul>\r\n</li>\r\n<li><strong>Dokumen Akademik:</strong>\r\n<ul>\r\n<li>Fotokopi rapor semester terakhir (bagi yang telah bersekolah sebelumnya).</li>\r\n<li>Surat keterangan dari sekolah asal (jika ada).</li>\r\n</ul>\r\n</li>\r\n<li><strong>Dokumen Tambahan (Jika Diperlukan):</strong>\r\n<ul>\r\n<li>Sertifikat prestasi akademik/non-akademik (jika ada).</li>\r\n<li>Surat rekomendasi dari sekolah sebelumnya (jika diperlukan).</li>\r\n<li>Surat keterangan sehat dari dokter.</li>\r\n</ul>\r\n</li>\r\n</ol>\r\n<h2><strong>Informasi Tambahan</strong></h2>\r\n<ul>\r\n<li>Semua dokumen harus diunggah dalam format PDF atau JPEG dengan ukuran maksimal 2MB.</li>\r\n<li>Informasi lebih lanjut mengenai jadwal pendaftaran, biaya pendidikan, dan detail lainnya dapat diakses melalui website resmi HAQI Learning Center atau menghubungi kontak administrasi.</li>\r\n</ul>\r\n<p>Mari bergabung dengan HAQI Learning Center dan wujudkan masa depan cerah bersama kami!</p>\r\n<p><strong>HAQI Learning Center - Membangun Karakter, Menginspirasi Prestasi!</strong></p>', '2026-01-01', '2026-12-01', '2026-12-31', 'Buka', '1741053964_069006e98ae67d4ee20b.jpeg', '2026-03-23 11:26:13'),
(2, 11, '2026/2027', 2, '2026', 'ppdb-tahap-2-tahun-ajaran-20262027', 'PPDB Tahap 2 - Tahun Ajaran 2026/2027', '<p><strong>Penerimaan Peserta Didik Baru (PPDB) HAQI Learning Center Tahun Ajaran 2026/2027</strong></p>\r\n<p>HAQI Learning Center membuka kesempatan bagi calon peserta didik baru untuk bergabung dalam lingkungan pendidikan berkualitas yang berorientasi pada pengembangan akademik dan karakter. Berikut adalah informasi mengenai proses Penerimaan Peserta Didik Baru (PPDB) Tahun Ajaran 2026/2027.</p>\r\n<h2><strong>Tahapan Pendaftaran</strong></h2>\r\n<h3>1. <strong>Pendaftaran Online</strong></h3>\r\n<p>Calon peserta didik harus melakukan pendaftaran secara online melalui website resmi HAQI Learning Center di [website resmi].</p>\r\n<ul>\r\n<li>Mengisi formulir pendaftaran dengan lengkap dan benar.</li>\r\n<li>Mengunggah dokumen persyaratan yang telah ditentukan.</li>\r\n<li>Menerima kode pendaftaran sebagai bukti pendaftaran.</li>\r\n</ul>\r\n<h3>2. <strong>Verifikasi Dokumen</strong></h3>\r\n<p>Tim administrasi akan melakukan verifikasi dokumen yang telah diunggah. Jika terdapat kekurangan, calon peserta didik akan diinformasikan untuk melengkapi dokumen dalam batas waktu yang telah ditentukan.</p>\r\n<h3>3. <strong>Tes Seleksi</strong></h3>\r\n<p>Calon peserta didik yang telah lolos tahap verifikasi dokumen akan mengikuti tes seleksi akademik dan wawancara. Tes seleksi mencakup:</p>\r\n<ul>\r\n<li>Tes akademik sesuai jenjang pendidikan.</li>\r\n<li>Wawancara calon peserta didik dan orang tua/wali.</li>\r\n</ul>\r\n<h3>4. <strong>Pengumuman Hasil Seleksi</strong></h3>\r\n<p>Hasil seleksi akan diumumkan melalui website resmi dan email yang telah didaftarkan.</p>\r\n<h3>5. <strong>Registrasi Ulang</strong></h3>\r\n<p>Peserta yang lolos seleksi harus melakukan registrasi ulang dengan:</p>\r\n<ul>\r\n<li>Membayar biaya pendidikan sesuai ketentuan.</li>\r\n<li>Mengumpulkan dokumen fisik ke kantor administrasi HAQI Learning Center.</li>\r\n<li>Mengikuti sesi orientasi bagi peserta didik baru.</li>\r\n</ul>\r\n<h2><strong>Persyaratan Dokumen</strong></h2>\r\n<p>Untuk mengikuti PPDB HAQI Learning Center Tahun Ajaran 2026/2027, calon peserta didik wajib melampirkan dokumen sebagai berikut:</p>\r\n<ol>\r\n<li><strong>Dokumen Umum:</strong>\r\n<ul>\r\n<li>Formulir pendaftaran yang telah diisi dan ditandatangani.</li>\r\n<li>Fotokopi Akta Kelahiran.</li>\r\n<li>Fotokopi Kartu Keluarga.</li>\r\n<li>Fotokopi KTP orang tua/wali.</li>\r\n<li>Pas foto berwarna ukuran 3x4 (3 lembar).</li>\r\n</ul>\r\n</li>\r\n<li><strong>Dokumen Akademik:</strong>\r\n<ul>\r\n<li>Fotokopi rapor semester terakhir (bagi yang telah bersekolah sebelumnya).</li>\r\n<li>Surat keterangan dari sekolah asal (jika ada).</li>\r\n</ul>\r\n</li>\r\n<li><strong>Dokumen Tambahan (Jika Diperlukan):</strong>\r\n<ul>\r\n<li>Sertifikat prestasi akademik/non-akademik (jika ada).</li>\r\n<li>Surat rekomendasi dari sekolah sebelumnya (jika diperlukan).</li>\r\n<li>Surat keterangan sehat dari dokter.</li>\r\n</ul>\r\n</li>\r\n</ol>\r\n<h2><strong>Informasi Tambahan</strong></h2>\r\n<ul>\r\n<li>Semua dokumen harus diunggah dalam format PDF atau JPEG dengan ukuran maksimal 2MB.</li>\r\n<li>Informasi lebih lanjut mengenai jadwal pendaftaran, biaya pendidikan, dan detail lainnya dapat diakses melalui website resmi HAQI Learning Center atau menghubungi kontak administrasi.</li>\r\n</ul>\r\n<p>Mari bergabung dengan HAQI Learning Center dan wujudkan masa depan cerah bersama kami!</p>\r\n<p><strong>HAQI Learning Center - Membangun Karakter, Menginspirasi Prestasi!</strong></p>', '2026-01-01', '2026-12-01', '2026-12-31', 'Buka', '1741063424_943aa660232fb50712a4.jpg', '2026-03-23 11:26:20');
