INSERT INTO `jenjang_pendidikan` (`id_jenjang_pendidikan`, `id_user`, `id_jenjang`, `slug_jenjang_pendidikan`, `judul_jenjang_pendidikan`, `ringkasan`, `isi`, `status_jenjang_pendidikan`, `jenis_jenjang_pendidikan`, `keywords`, `gambar`, `icon`, `hits`, `urutan`, `tanggal_post`, `tanggal_publish`, `tanggal`) VALUES
(15, 11, 14, 'pesantren-smp', 'PESANTREN + SMP', 'Perpaduan Smp dan Pesantren', '<section id=\"pendidikan-terpadu\" style=\"max-width: 1100px; margin: 0 auto; font-family: \'Segoe UI\', \'Poppins\', system-ui, -apple-system, sans-serif; background: #ffffff; border-radius: 28px; box-shadow: 0 20px 40px rgba(0,0,0,0.05); overflow: hidden;\">\r\n    \r\n    <!-- Header dengan gradien hijau emas yang elegan -->\r\n    <header style=\"background: linear-gradient(135deg, #1a5f3a, #2c8a5a, #e6bc7e); padding: 50px 30px 45px; text-align: center; color: white; position: relative;\">\r\n        <div style=\"position: absolute; top: 20px; right: 20px; opacity: 0.08; font-size: 100px;\">\r\n            <i class=\"fas fa-handshake\"></i>\r\n        </div>\r\n        <div style=\"font-size: 55px; margin-bottom: 15px;\">\r\n            <i class=\"fas fa-handshake\" style=\"background: rgba(255,255,255,0.2); padding: 15px 22px; border-radius: 60px;\"></i>\r\n        </div>\r\n        <h1 style=\"font-size: 2rem; margin: 0 0 12px 0; font-weight: 700; letter-spacing: -0.5px;\">\r\n            Pendidikan Terpadu <br> Yayasan Al-Hikamussalafie\r\n        </h1>\r\n        <p style=\"font-size: 1rem; opacity: 0.95; margin: 0 auto; max-width: 650px; line-height: 1.5;\">\r\n            <i class=\"fas fa-quote-left\"></i> Sinergi Pendidikan Islam Ideal: Tradisi Salafiyah & Pendidikan Modern Formal <i class=\"fas fa-quote-right\"></i>\r\n        </p>\r\n        <div style=\"margin-top: 20px; display: flex; justify-content: center; gap: 12px; flex-wrap: wrap;\">\r\n            <span style=\"background: rgba(255,255,255,0.2); padding: 6px 18px; border-radius: 40px; font-size: 0.8rem;\">\r\n                <i class=\"fas fa-mosque\"></i> Pondok Pesantren Al-Hikamussalafie\r\n            </span>\r\n            <span style=\"background: rgba(255,255,255,0.2); padding: 6px 18px; border-radius: 40px; font-size: 0.8rem;\">\r\n                <i class=\"fas fa-school\"></i> SMP Nusantara Cipunagara\r\n            </span>\r\n        </div>\r\n    </header>\r\n\r\n    <!-- Deskripsi Awal dengan highlight -->\r\n    <div style=\"padding: 30px 32px 0 32px; background: #ffffff;\">\r\n        <div style=\"background: linear-gradient(115deg, #fef9ef, #fffcf5); border-radius: 24px; padding: 28px 30px; border-left: 6px solid #e6bc7e;\">\r\n            <p style=\"line-height: 1.75; text-align: justify; color: #2d3e32; font-size: 1rem; margin: 0;\">\r\n                <strong>Pondok Pesantren Al-Hikamussalafie & SMP Nusantara Cipunagara</strong> adalah sinergi pendidikan Islam ideal \r\n                yang memadukan tradisi Salafiyah dengan pendidikan modern formal. Berdiri di atas landasan sejarah perjuangan dakwah \r\n                sejak <strong>1996</strong>, kami hadir sebagai jawaban bagi orang tua yang menginginkan putra-putrinya meraih \r\n                <strong>ijazah nasional (SMP)</strong> sekaligus menguasai ilmu agama yang mendalam \r\n                <strong>(Santri Mukim)</strong>.\r\n            </p>\r\n        </div>\r\n    </div>\r\n\r\n    <!-- Konten Utama -->\r\n    <article style=\"padding: 30px 32px 35px 32px; background: #ffffff;\">\r\n        \r\n        <!-- 1) Visi & Misi Terpadu -->\r\n        <div style=\"margin-bottom: 45px;\">\r\n            <div style=\"display: flex; align-items: center; gap: 12px; margin-bottom: 20px; border-left: 4px solid #e6bc7e; padding-left: 18px;\">\r\n                <i class=\"fas fa-bullseye\" style=\"color: #e6bc7e; font-size: 1.6rem;\"></i>\r\n                <h2 style=\"margin: 0; color: #1e3a2f; font-size: 1.5rem; font-weight: 600;\">Visi & Misi Terpadu</h2>\r\n            </div>\r\n            <div style=\"background: #fefcf5; border-radius: 24px; padding: 28px; border: 1px solid #ebe1cf;\">\r\n                <div style=\"margin-bottom: 28px;\">\r\n                    <h3 style=\"color: #2a7a4a; margin-bottom: 12px; display: flex; align-items: center; gap: 8px;\">\r\n                        <i class=\"fas fa-eye\"></i> Visi\r\n                    </h3>\r\n                    <p style=\"font-style: italic; color: #3a5a48; font-size: 1rem; line-height: 1.6; margin: 0; padding-left: 20px; border-left: 3px solid #e6bc7e;\">\r\n                        \"Mewujudkan Generasi Qur\'ani yang Berwawasan Luas, Berilmu, Mandiri, dan Berakhlakul Karimah.\"\r\n                    </p>\r\n                </div>\r\n                <div>\r\n                    <h3 style=\"color: #2a7a4a; margin-bottom: 15px; display: flex; align-items: center; gap: 8px;\">\r\n                        <i class=\"fas fa-list-check\"></i> Misi\r\n                    </h3>\r\n                    <ul style=\"list-style-type: none; padding-left: 0; margin: 0;\">\r\n                        <li style=\"margin-bottom: 14px; display: flex; gap: 12px; align-items: flex-start;\">\r\n                            <i class=\"fas fa-check-circle\" style=\"color: #27ae60; margin-top: 3px;\"></i>\r\n                            <span style=\"color: #2d3e32;\">Menyelenggarakan pendidikan formal yang selaras dengan nilai luhur pesantren.</span>\r\n                        </li>\r\n                        <li style=\"margin-bottom: 14px; display: flex; gap: 12px; align-items: flex-start;\">\r\n                            <i class=\"fas fa-check-circle\" style=\"color: #27ae60; margin-top: 3px;\"></i>\r\n                            <span style=\"color: #2d3e32;\">Melestarikan tradisi kitab kuning dan tahfidz Al-Qur\'an.</span>\r\n                        </li>\r\n                        <li style=\"margin-bottom: 14px; display: flex; gap: 12px; align-items: flex-start;\">\r\n                            <i class=\"fas fa-check-circle\" style=\"color: #27ae60; margin-top: 3px;\"></i>\r\n                            <span style=\"color: #2d3e32;\">Membentuk karakter disiplin, ikhlas, dan beradab (Adabul Karimah).</span>\r\n                        </li>\r\n                        <li style=\"margin-bottom: 14px; display: flex; gap: 12px; align-items: flex-start;\">\r\n                            <i class=\"fas fa-check-circle\" style=\"color: #27ae60; margin-top: 3px;\"></i>\r\n                            <span style=\"color: #2d3e32;\">Mengembangkan potensi akademik dan kreativitas siswa di lingkungan yang inklusif.</span>\r\n                        </li>\r\n                    </ul>\r\n                </div>\r\n            </div>\r\n        </div>\r\n\r\n        <!-- 2) Program Unggulan (Pesantren + SMP) -->\r\n        <div style=\"margin-bottom: 45px;\">\r\n            <div style=\"display: flex; align-items: center; gap: 12px; margin-bottom: 20px; border-left: 4px solid #2a7a4a; padding-left: 18px;\">\r\n                <i class=\"fas fa-star-of-life\" style=\"color: #2a7a4a; font-size: 1.6rem;\"></i>\r\n                <h2 style=\"margin: 0; color: #1e3a2f; font-size: 1.5rem; font-weight: 600;\">Program Unggulan <span style=\"font-size: 0.9rem;\">(Pesantren + SMP)</span></h2>\r\n            </div>\r\n            <div style=\"display: flex; flex-wrap: wrap; gap: 20px;\">\r\n                <div style=\"flex: 1; min-width: 250px; background: #f9fbf7; border-radius: 20px; padding: 22px; border: 1px solid #e8eedf; transition: transform 0.2s;\">\r\n                    <div style=\"background: linear-gradient(135deg, #2a7a4a20, #e6bc7e20); width: 55px; height: 55px; border-radius: 18px; display: flex; align-items: center; justify-content: center; margin-bottom: 15px;\">\r\n                        <i class=\"fas fa-layer-group\" style=\"color: #2a7a4a; font-size: 1.5rem;\"></i>\r\n                    </div>\r\n                    <h3 style=\"margin: 0 0 10px 0; color: #2a7a4a; font-size: 1.1rem;\">Double Curriculum</h3>\r\n                    <p style=\"margin: 0; color: #5a6e5e; line-height: 1.5; font-size: 0.9rem;\">Integrasi Kurikulum Nasional (Kemendikbud) dengan Kurikulum Salafiyah (Kitab Kuning: Fikih, Tauhid, Nahwu, Shorof).</p>\r\n                </div>\r\n                <div style=\"flex: 1; min-width: 250px; background: #f9fbf7; border-radius: 20px; padding: 22px; border: 1px solid #e8eedf;\">\r\n                    <div style=\"background: linear-gradient(135deg, #2a7a4a20, #e6bc7e20); width: 55px; height: 55px; border-radius: 18px; display: flex; align-items: center; justify-content: center; margin-bottom: 15px;\">\r\n                        <i class=\"fas fa-quran\" style=\"color: #2a7a4a; font-size: 1.5rem;\"></i>\r\n                    </div>\r\n                    <h3 style=\"margin: 0 0 10px 0; color: #2a7a4a; font-size: 1.1rem;\">Tahsin & Tahfidz Intensif</h3>\r\n                    <p style=\"margin: 0; color: #5a6e5e; line-height: 1.5; font-size: 0.9rem;\">Bimbingan membaca Al-Qur\'an yang tartil dan program hafalan harian bagi seluruh siswa.</p>\r\n                </div>\r\n                <div style=\"flex: 1; min-width: 250px; background: #f9fbf7; border-radius: 20px; padding: 22px; border: 1px solid #e8eedf;\">\r\n                    <div style=\"background: linear-gradient(135deg, #2a7a4a20, #e6bc7e20); width: 55px; height: 55px; border-radius: 18px; display: flex; align-items: center; justify-content: center; margin-bottom: 15px;\">\r\n                        <i class=\"fas fa-hands-praying\" style=\"color: #2a7a4a; font-size: 1.5rem;\"></i>\r\n                    </div>\r\n                    <h3 style=\"margin: 0 0 10px 0; color: #2a7a4a; font-size: 1.1rem;\">Pembiasaan Karakter & Amalan Sunnah</h3>\r\n                    <p style=\"margin: 0; color: #5a6e5e; line-height: 1.5; font-size: 0.9rem;\">Shalat berjamaah, puasa sunnah, zikir rutin, serta pembinaan kepemimpinan melalui organisasi kesiswaan.</p>\r\n                </div>\r\n                <div style=\"flex: 1; min-width: 250px; background: #f9fbf7; border-radius: 20px; padding: 22px; border: 1px solid #e8eedf;\">\r\n                    <div style=\"background: linear-gradient(135deg, #2a7a4a20, #e6bc7e20); width: 55px; height: 55px; border-radius: 18px; display: flex; align-items: center; justify-content: center; margin-bottom: 15px;\">\r\n                        <i class=\"fas fa-hand-holding-heart\" style=\"color: #2a7a4a; font-size: 1.5rem;\"></i>\r\n                    </div>\r\n                    <h3 style=\"margin: 0 0 10px 0; color: #2a7a4a; font-size: 1.1rem;\">Social & Community Project</h3>\r\n                    <p style=\"margin: 0; color: #5a6e5e; line-height: 1.5; font-size: 0.9rem;\">Melatih santri terjun langsung dalam kegiatan sosial untuk memberi manfaat nyata bagi masyarakat Cipunagara.</p>\r\n                </div>\r\n            </div>\r\n        </div>\r\n\r\n        <!-- 3) Kurikulum & Lingkungan Belajar -->\r\n        <div style=\"margin-bottom: 45px;\">\r\n            <div style=\"display: flex; align-items: center; gap: 12px; margin-bottom: 20px; border-left: 4px solid #e6bc7e; padding-left: 18px;\">\r\n                <i class=\"fas fa-chalkboard\" style=\"color: #e6bc7e; font-size: 1.6rem;\"></i>\r\n                <h2 style=\"margin: 0; color: #1e3a2f; font-size: 1.5rem; font-weight: 600;\">Kurikulum & Lingkungan Belajar</h2>\r\n            </div>\r\n            <div style=\"display: flex; flex-wrap: wrap; gap: 20px;\">\r\n                <div style=\"flex: 1; min-width: 250px; background: #fefcf5; border-radius: 20px; padding: 22px; border: 1px solid #e8e0cf;\">\r\n                    <i class=\"fas fa-file-alt\" style=\"color: #2a7a4a; font-size: 2rem; margin-bottom: 12px; display: block;\"></i>\r\n                    <h3 style=\"margin: 0 0 8px 0; color: #2a7a4a; font-size: 1rem;\">Pendidikan Formal Berizin Resmi</h3>\r\n                    <p style=\"margin: 0; color: #5a6e5e; font-size: 0.85rem;\">SMP Nusantara telah memiliki izin lingkungan dan dukungan sinergi pendidikan dari SMPN Cipunagara.</p>\r\n                </div>\r\n                <div style=\"flex: 1; min-width: 250px; background: #fefcf5; border-radius: 20px; padding: 22px; border: 1px solid #e8e0cf;\">\r\n                    <i class=\"fas fa-tree\" style=\"color: #2a7a4a; font-size: 2rem; margin-bottom: 12px; display: block;\"></i>\r\n                    <h3 style=\"margin: 0 0 8px 0; color: #2a7a4a; font-size: 1rem;\">Ekosistem Islami yang Kondusif</h3>\r\n                    <p style=\"margin: 0; color: #5a6e5e; font-size: 0.85rem;\">Terletak di kawasan pesantren yang tenang, menjauhkan siswa dari pengaruh negatif lingkungan luar.</p>\r\n                </div>\r\n                <div style=\"flex: 1; min-width: 250px; background: #fefcf5; border-radius: 20px; padding: 22px; border: 1px solid #e8e0cf;\">\r\n                    <i class=\"fas fa-lightbulb\" style=\"color: #2a7a4a; font-size: 2rem; margin-bottom: 12px; display: block;\"></i>\r\n                    <h3 style=\"margin: 0 0 8px 0; color: #2a7a4a; font-size: 1rem;\">Pembelajaran Aktif & Inovatif</h3>\r\n                    <p style=\"margin: 0; color: #5a6e5e; font-size: 0.85rem;\">Pendekatan KBM modern yang mendorong kreativitas tanpa meninggalkan akar spiritualitas.</p>\r\n                </div>\r\n            </div>\r\n        </div>\r\n\r\n        <!-- 4) Mengapa Memilih Kami? (Card Utama) -->\r\n        <div style=\"background: linear-gradient(105deg, #eef6ea, #e8f0e2); border-radius: 28px; padding: 32px 35px; margin-top: 20px;\">\r\n            <div style=\"display: flex; align-items: center; gap: 12px; margin-bottom: 20px;\">\r\n                <i class=\"fas fa-question-circle\" style=\"color: #2a7a4a; font-size: 2rem;\"></i>\r\n                <h2 style=\"margin: 0; color: #1e3a2f; font-size: 1.4rem; font-weight: 700;\">Mengapa Memilih Kami?</h2>\r\n            </div>\r\n            <div style=\"display: flex; flex-wrap: wrap; gap: 25px; align-items: center;\">\r\n                <div style=\"flex: 2;\">\r\n                    <p style=\"line-height: 1.7; color: #2d4a3a; text-align: justify; margin-bottom: 15px;\">\r\n                        Kami menawarkan solusi <strong>\"Satu Atap\"</strong>: Anak mendapatkan pendidikan SMP yang legal di bawah kepemimpinan \r\n                        <strong>Bpk. Hamdan Hidayat, S.H.</strong>, namun tetap mendapatkan bekal agama yang murni di bawah asuhan \r\n                        <strong>Yayasan Al-Hikamussalafie</strong>. Di sini, putra-putri Anda dididik untuk \r\n                        <strong>pintar secara intelektual, terampil secara sosial, dan teguh secara iman</strong>.\r\n                    </p>\r\n                </div>\r\n                <div style=\"flex: 1; text-align: center;\">\r\n                    <div style=\"background: white; border-radius: 50%; width: 100px; height: 100px; display: inline-flex; align-items: center; justify-content: center; box-shadow: 0 8px 20px rgba(0,0,0,0.1);\">\r\n                        <i class=\"fas fa-graduation-cap\" style=\"font-size: 3rem; color: #2a7a4a;\"></i>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n\r\n        <!-- Informasi Tambahan Sinergi -->\r\n        <div style=\"margin-top: 35px; display: flex; flex-wrap: wrap; gap: 15px; background: #f9faf5; border-radius: 20px; padding: 20px 25px;\">\r\n            <div style=\"flex: 1; text-align: center; padding: 10px;\">\r\n                <i class=\"fas fa-scroll\" style=\"color: #e6bc7e; font-size: 1.5rem;\"></i>\r\n                <h4 style=\"margin: 8px 0 4px; color: #2a7a4a;\">Tradisi Salafiyah</h4>\r\n                <p style=\"margin: 0; font-size: 0.75rem; color: #6a7e6a;\">Kitab Kuning & Tahfidz</p>\r\n            </div>\r\n            <div style=\"flex: 1; text-align: center; padding: 10px;\">\r\n                <i class=\"fas fa-school\" style=\"color: #e6bc7e; font-size: 1.5rem;\"></i>\r\n                <h4 style=\"margin: 8px 0 4px; color: #2a7a4a;\">Pendidikan Modern</h4>\r\n                <p style=\"margin: 0; font-size: 0.75rem; color: #6a7e6a;\">Kurikulum Nasional Berizin</p>\r\n            </div>\r\n            <div style=\"flex: 1; text-align: center; padding: 10px;\">\r\n                <i class=\"fas fa-handshake\" style=\"color: #e6bc7e; font-size: 1.5rem;\"></i>\r\n                <h4 style=\"margin: 8px 0 4px; color: #2a7a4a;\">Sinergi Pesantren & SMP</h4>\r\n                <p style=\"margin: 0; font-size: 0.75rem; color: #6a7e6a;\">Satu Atap, Dua Capaian</p>\r\n            </div>\r\n        </div>\r\n\r\n        <!-- Footer Penutup -->\r\n        <div style=\"margin-top: 30px; padding-top: 20px; border-top: 1px solid #dee6da; text-align: center; font-size: 0.75rem; color: #7a927a; display: flex; flex-wrap: wrap; justify-content: center; gap: 28px;\">\r\n            <span><i class=\"fas fa-mosque\"></i> Ponpes Al-Hikamussalafie (Sejak 1996)</span>\r\n            <span><i class=\"fas fa-school\"></i> SMP Nusantara Cipunagara (4 Januari 2022)</span>\r\n            <span><i class=\"fas fa-user-tie\"></i> Kepala Sekolah: Hamdan Hidayat, S.H.</span>\r\n        </div>\r\n        <div style=\"text-align: center; margin-top: 20px; font-weight: 500; color: #2c6b48;\">\r\n            <i class=\"fas fa-leaf\"></i> Satu Atap, Dua Capaian: Ijazah Nasional & Kedalaman Ilmu Agama <i class=\"fas fa-leaf\"></i>\r\n        </div>\r\n    </article>\r\n</section>\r\n\r\n<!-- Font Awesome CDN -->\r\n<link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.0.0-beta3/css/all.min.css\">', 'Publish', 'Jenjang', 'TKIT Haqi Junior merupakan bagian dari Yayasan Haqi Learning Center yang berfokus pada pendidikan usia dini berkualitas dengan landasan nilai-nilai Islam.', '1774418111_e6d346cd3d699b40fabf.png', '', 28, 0, '2025-03-05 22:58:21', '2025-03-05 22:57:00', '2026-03-25 05:55:14'),
(16, 11, 15, 'pesantren-al-hikamussalfie', 'PESANTREN AL-HIKAMUSSALFIE', 'Yayasan Al-Hikamussalafie melalui Pondok Pesantren Al-Hikamussalafie dan SMP Nusantara Cipunagara menyelenggarakan pendidikan Islam terpadu yang memadukan tradisi kitab kuning dengan kurikulum nasional. Berlandaskan sejarah dakwah sejak 1996, kami berkomitmen mencetak generasi qur\'ani yang cerdas secara akademik, mandiri, dan berakhlakul karimah.', '<section id=\"profil-ponpes\" style=\"max-width: 1100px; margin: 0 auto; font-family: \'Segoe UI\', \'Poppins\', system-ui, -apple-system, sans-serif; background: #ffffff; border-radius: 28px; box-shadow: 0 20px 40px rgba(0,0,0,0.05); overflow: hidden;\">\r\n    \r\n    <!-- Header dengan gradien hijau gelap yang elegan -->\r\n    <header style=\"background: linear-gradient(135deg, #0f4a2a, #1e6b3e, #2c7a4a); padding: 50px 30px 45px; text-align: center; color: white; position: relative;\">\r\n        <div style=\"position: absolute; top: 20px; right: 20px; opacity: 0.08; font-size: 100px;\">\r\n            <i class=\"fas fa-mosque\"></i>\r\n        </div>\r\n        <div style=\"font-size: 55px; margin-bottom: 15px;\">\r\n            <i class=\"fas fa-mosque\" style=\"background: rgba(255,255,255,0.2); padding: 15px 22px; border-radius: 60px;\"></i>\r\n        </div>\r\n        <h1 style=\"font-size: 2.3rem; margin: 0 0 12px 0; font-weight: 700; letter-spacing: -0.5px;\">\r\n            Pondok Pesantren Al Hikamussalafie\r\n        </h1>\r\n        <p style=\"font-size: 1rem; opacity: 0.95; margin: 0 auto; max-width: 600px; line-height: 1.5;\">\r\n            <i class=\"fas fa-quote-left\"></i> Membumikan Al-Qur\'an dan Sunnah, Menebar Rahmat bagi Semesta <i class=\"fas fa-quote-right\"></i>\r\n        </p>\r\n        <div style=\"margin-top: 20px; display: flex; justify-content: center; gap: 12px; flex-wrap: wrap;\">\r\n            <span style=\"background: rgba(255,255,255,0.2); padding: 6px 18px; border-radius: 40px; font-size: 0.8rem;\">\r\n                <i class=\"fas fa-calendar-alt\"></i> Berdiri: 14 Januari 1996\r\n            </span>\r\n            <span style=\"background: rgba(255,255,255,0.2); padding: 6px 18px; border-radius: 40px; font-size: 0.8rem;\">\r\n                <i class=\"fas fa-moon\"></i> 23 Sya\'ban 1416 H\r\n            </span>\r\n        </div>\r\n    </header>\r\n\r\n    <!-- Badge Informasi -->\r\n    <div style=\"display: flex; flex-wrap: wrap; gap: 20px; background: linear-gradient(95deg, #fafaf5, #f3f5ef); padding: 20px 30px; border-bottom: 1px solid #e0e8dc;\">\r\n        <div style=\"display: flex; align-items: center; gap: 12px;\">\r\n            <span style=\"background: #1e6b3e; width: 38px; height: 38px; display: inline-flex; align-items: center; justify-content: center; border-radius: 50%; color: white;\"><i class=\"fas fa-building\"></i></span>\r\n            <div>\r\n                <div style=\"font-size: 0.7rem; color: #5a7a6a;\">YAYASAN</div>\r\n                <div style=\"font-weight: 700; color: #1e5631;\">Al Hikamussalafie</div>\r\n            </div>\r\n        </div>\r\n        <div style=\"display: flex; align-items: center; gap: 12px;\">\r\n            <span style=\"background: #1e6b3e; width: 38px; height: 38px; display: inline-flex; align-items: center; justify-content: center; border-radius: 50%; color: white;\"><i class=\"fas fa-tag\"></i></span>\r\n            <div>\r\n                <div style=\"font-size: 0.7rem; color: #5a7a6a;\">NAMA AWAL</div>\r\n                <div style=\"font-weight: 700; color: #1e5631;\">PP Syarif Hidayatullah</div>\r\n            </div>\r\n        </div>\r\n        <div style=\"display: flex; align-items: center; gap: 12px;\">\r\n            <span style=\"background: #1e6b3e; width: 38px; height: 38px; display: inline-flex; align-items: center; justify-content: center; border-radius: 50%; color: white;\"><i class=\"fas fa-map-marker-alt\"></i></span>\r\n            <div>\r\n                <div style=\"font-size: 0.7rem; color: #5a7a6a;\">LOKASI</div>\r\n                <div style=\"font-weight: 700; color: #1e5631;\">Cipunagara, Subang</div>\r\n            </div>\r\n        </div>\r\n    </div>\r\n\r\n    <!-- Konten Utama -->\r\n    <article style=\"padding: 35px 32px; background: #ffffff;\">\r\n        \r\n        <!-- Deskripsi Awal -->\r\n        <div style=\"margin-bottom: 40px;\">\r\n            <p style=\"line-height: 1.75; text-align: justify; color: #2d3e32; font-size: 1rem;\">\r\n                <strong>Pondok Pesantren Al Hikamussalafie</strong> merupakan bagian dari \r\n                <strong>Yayasan Al Hikamussalafie</strong> yang berfokus pada pendidikan Islam salaf dan pembinaan akhlak mulia \r\n                dengan landasan murni Al-Qur\'an dan Sunnah. Berdiri sejak <strong>14 Januari 1996</strong> \r\n                (sebelumnya bernama PP Syarif Hidayatullah), pesantren ini lahir sebagai <strong>mercusuar dakwah</strong> \r\n                untuk membawa masyarakat menuju cahaya Islam yang kaffah.\r\n            </p>\r\n        </div>\r\n\r\n        <!-- 1) Visi & Misi -->\r\n        <div style=\"margin-bottom: 45px;\">\r\n            <div style=\"display: flex; align-items: center; gap: 12px; margin-bottom: 20px; border-left: 4px solid #e6bc7e; padding-left: 18px;\">\r\n                <i class=\"fas fa-bullseye\" style=\"color: #e6bc7e; font-size: 1.6rem;\"></i>\r\n                <h2 style=\"margin: 0; color: #1e3a2f; font-size: 1.5rem; font-weight: 600;\">Visi & Misi</h2>\r\n            </div>\r\n            <div style=\"background: #fefcf5; border-radius: 24px; padding: 28px; border: 1px solid #ebe1cf;\">\r\n                <div style=\"margin-bottom: 28px;\">\r\n                    <h3 style=\"color: #1e6b3e; margin-bottom: 12px; display: flex; align-items: center; gap: 8px;\">\r\n                        <i class=\"fas fa-eye\"></i> Visi\r\n                    </h3>\r\n                    <p style=\"font-style: italic; color: #3a5a48; font-size: 1rem; line-height: 1.6; margin: 0; padding-left: 20px; border-left: 3px solid #e6bc7e;\">\r\n                        \"Mewujudkan Generasi Berilmu, Berakhlak Mulia, dan Bermanfaat bagi Agama serta Bangsa.\"\r\n                    </p>\r\n                </div>\r\n                <div>\r\n                    <h3 style=\"color: #1e6b3e; margin-bottom: 15px; display: flex; align-items: center; gap: 8px;\">\r\n                        <i class=\"fas fa-list-check\"></i> Misi\r\n                    </h3>\r\n                    <ul style=\"list-style-type: none; padding-left: 0; margin: 0;\">\r\n                        <li style=\"margin-bottom: 14px; display: flex; gap: 12px; align-items: flex-start;\">\r\n                            <i class=\"fas fa-check-circle\" style=\"color: #27ae60; margin-top: 3px;\"></i>\r\n                            <span style=\"color: #2d3e32;\">Menanamkan akidah Islamiyah yang kuat dan menjauhkan diri dari praktik kemusyrikan.</span>\r\n                        </li>\r\n                        <li style=\"margin-bottom: 14px; display: flex; gap: 12px; align-items: flex-start;\">\r\n                            <i class=\"fas fa-check-circle\" style=\"color: #27ae60; margin-top: 3px;\"></i>\r\n                            <span style=\"color: #2d3e32;\">Melestarikan tradisi keilmuan Islam melalui pengajaran Kitab Kuning.</span>\r\n                        </li>\r\n                        <li style=\"margin-bottom: 14px; display: flex; gap: 12px; align-items: flex-start;\">\r\n                            <i class=\"fas fa-check-circle\" style=\"color: #27ae60; margin-top: 3px;\"></i>\r\n                            <span style=\"color: #2d3e32;\">Membentuk karakter santri yang disiplin, ikhlas, dan beradab.</span>\r\n                        </li>\r\n                        <li style=\"margin-bottom: 14px; display: flex; gap: 12px; align-items: flex-start;\">\r\n                            <i class=\"fas fa-check-circle\" style=\"color: #27ae60; margin-top: 3px;\"></i>\r\n                            <span style=\"color: #2d3e32;\">Menyelenggarakan pendidikan yang memadukan spiritualitas pesantren dengan kebutuhan zaman.</span>\r\n                        </li>\r\n                    </ul>\r\n                </div>\r\n            </div>\r\n        </div>\r\n\r\n        <!-- 2) Program Unggulan -->\r\n        <div style=\"margin-bottom: 45px;\">\r\n            <div style=\"display: flex; align-items: center; gap: 12px; margin-bottom: 20px; border-left: 4px solid #1e6b3e; padding-left: 18px;\">\r\n                <i class=\"fas fa-star\" style=\"color: #1e6b3e; font-size: 1.6rem;\"></i>\r\n                <h2 style=\"margin: 0; color: #1e3a2f; font-size: 1.5rem; font-weight: 600;\">Program Unggulan</h2>\r\n            </div>\r\n            <div style=\"display: flex; flex-wrap: wrap; gap: 20px;\">\r\n                <div style=\"flex: 1; min-width: 240px; background: #f9fbf7; border-radius: 20px; padding: 22px; border: 1px solid #e8eedf;\">\r\n                    <div style=\"background: #1e6b3e15; width: 50px; height: 50px; border-radius: 16px; display: flex; align-items: center; justify-content: center; margin-bottom: 15px;\">\r\n                        <i class=\"fas fa-book\" style=\"color: #1e6b3e; font-size: 1.5rem;\"></i>\r\n                    </div>\r\n                    <h3 style=\"margin: 0 0 10px 0; color: #1e6b3e; font-size: 1.1rem;\">Kajian Kitab Klasik (Kitab Kuning)</h3>\r\n                    <p style=\"margin: 0; color: #5a6e5e; line-height: 1.5; font-size: 0.9rem;\">Pendalaman ilmu fikih, tauhid, dan tata bahasa Arab (Nahwu & Shorof).</p>\r\n                </div>\r\n                <div style=\"flex: 1; min-width: 240px; background: #f9fbf7; border-radius: 20px; padding: 22px; border: 1px solid #e8eedf;\">\r\n                    <div style=\"background: #1e6b3e15; width: 50px; height: 50px; border-radius: 16px; display: flex; align-items: center; justify-content: center; margin-bottom: 15px;\">\r\n                        <i class=\"fas fa-quran\" style=\"color: #1e6b3e; font-size: 1.5rem;\"></i>\r\n                    </div>\r\n                    <h3 style=\"margin: 0 0 10px 0; color: #1e6b3e; font-size: 1.1rem;\">Tahsin & Tahfidz Al-Qur\'an</h3>\r\n                    <p style=\"margin: 0; color: #5a6e5e; line-height: 1.5; font-size: 0.9rem;\">Bimbingan membaca Al-Qur\'an yang tartil dan program hafalan harian.</p>\r\n                </div>\r\n                <div style=\"flex: 1; min-width: 240px; background: #f9fbf7; border-radius: 20px; padding: 22px; border: 1px solid #e8eedf;\">\r\n                    <div style=\"background: #1e6b3e15; width: 50px; height: 50px; border-radius: 16px; display: flex; align-items: center; justify-content: center; margin-bottom: 15px;\">\r\n                        <i class=\"fas fa-hands-praying\" style=\"color: #1e6b3e; font-size: 1.5rem;\"></i>\r\n                    </div>\r\n                    <h3 style=\"margin: 0 0 10px 0; color: #1e6b3e; font-size: 1.1rem;\">Pembiasaan Amalan Sunnah</h3>\r\n                    <p style=\"margin: 0; color: #5a6e5e; line-height: 1.5; font-size: 0.9rem;\">Shalat berjamaah, puasa sunnah, dan zikir rutin.</p>\r\n                </div>\r\n                <div style=\"flex: 1; min-width: 240px; background: #f9fbf7; border-radius: 20px; padding: 22px; border: 1px solid #e8eedf;\">\r\n                    <div style=\"background: #1e6b3e15; width: 50px; height: 50px; border-radius: 16px; display: flex; align-items: center; justify-content: center; margin-bottom: 15px;\">\r\n                        <i class=\"fas fa-hand-holding-heart\" style=\"color: #1e6b3e; font-size: 1.5rem;\"></i>\r\n                    </div>\r\n                    <h3 style=\"margin: 0 0 10px 0; color: #1e6b3e; font-size: 1.1rem;\">Dakwah Kemasyarakatan</h3>\r\n                    <p style=\"margin: 0; color: #5a6e5e; line-height: 1.5; font-size: 0.9rem;\">Melatih santri untuk terjun langsung memberikan manfaat di tengah masyarakat.</p>\r\n                </div>\r\n                <div style=\"flex: 1; min-width: 240px; background: #f9fbf7; border-radius: 20px; padding: 22px; border: 1px solid #e8eedf;\">\r\n                    <div style=\"background: #1e6b3e15; width: 50px; height: 50px; border-radius: 16px; display: flex; align-items: center; justify-content: center; margin-bottom: 15px;\">\r\n                        <i class=\"fas fa-school\" style=\"color: #1e6b3e; font-size: 1.5rem;\"></i>\r\n                    </div>\r\n                    <h3 style=\"margin: 0 0 10px 0; color: #1e6b3e; font-size: 1.1rem;\">Integrasi Pendidikan Formal</h3>\r\n                    <p style=\"margin: 0; color: #5a6e5e; line-height: 1.5; font-size: 0.9rem;\">Akses langsung ke pendidikan formal melalui SMP Nusantara Cipunagara di lingkungan pesantren.</p>\r\n                </div>\r\n            </div>\r\n        </div>\r\n\r\n        <!-- 3) Kurikulum Unggulan -->\r\n        <div style=\"margin-bottom: 45px;\">\r\n            <div style=\"display: flex; align-items: center; gap: 12px; margin-bottom: 20px; border-left: 4px solid #e6bc7e; padding-left: 18px;\">\r\n                <i class=\"fas fa-graduation-cap\" style=\"color: #e6bc7e; font-size: 1.6rem;\"></i>\r\n                <h2 style=\"margin: 0; color: #1e3a2f; font-size: 1.5rem; font-weight: 600;\">Kurikulum Unggulan</h2>\r\n            </div>\r\n            <div style=\"display: flex; flex-wrap: wrap; gap: 20px;\">\r\n                <div style=\"flex: 1; min-width: 220px; background: #fefcf5; border-radius: 20px; padding: 20px; border: 1px solid #e8e0cf;\">\r\n                    <i class=\"fas fa-scroll\" style=\"color: #1e6b3e; font-size: 1.8rem; margin-bottom: 12px; display: block;\"></i>\r\n                    <h3 style=\"margin: 0 0 8px 0; color: #1e6b3e; font-size: 1rem;\">Kurikulum Salafiyah</h3>\r\n                    <p style=\"margin: 0; color: #5a6e5e; font-size: 0.85rem;\">Menggunakan metode tradisional yang teruji dalam mencetak ulama dan tokoh agama.</p>\r\n                </div>\r\n                <div style=\"flex: 1; min-width: 220px; background: #fefcf5; border-radius: 20px; padding: 20px; border: 1px solid #e8e0cf;\">\r\n                    <i class=\"fas fa-heart\" style=\"color: #1e6b3e; font-size: 1.8rem; margin-bottom: 12px; display: block;\"></i>\r\n                    <h3 style=\"margin: 0 0 8px 0; color: #1e6b3e; font-size: 1rem;\">Penguatan Akidah & Akhlak</h3>\r\n                    <p style=\"margin: 0; color: #5a6e5e; font-size: 0.85rem;\">Fokus utama dalam membentengi santri dari pengaruh negatif lingkungan luar.</p>\r\n                </div>\r\n                <div style=\"flex: 1; min-width: 220px; background: #fefcf5; border-radius: 20px; padding: 20px; border: 1px solid #e8e0cf;\">\r\n                    <i class=\"fas fa-book-quran\" style=\"color: #1e6b3e; font-size: 1.8rem; margin-bottom: 12px; display: block;\"></i>\r\n                    <h3 style=\"margin: 0 0 8px 0; color: #1e6b3e; font-size: 1rem;\">Literasi Qur\'ani</h3>\r\n                    <p style=\"margin: 0; color: #5a6e5e; font-size: 0.85rem;\">Pengembangan kemampuan baca-tulis Al-Qur\'an secara mendalam sejak dini.</p>\r\n                </div>\r\n                <div style=\"flex: 1; min-width: 220px; background: #fefcf5; border-radius: 20px; padding: 20px; border: 1px solid #e8e0cf;\">\r\n                    <i class=\"fas fa-hand-sparkles\" style=\"color: #1e6b3e; font-size: 1.8rem; margin-bottom: 12px; display: block;\"></i>\r\n                    <h3 style=\"margin: 0 0 8px 0; color: #1e6b3e; font-size: 1rem;\">Pendidikan Berbasis Keikhlasan</h3>\r\n                    <p style=\"margin: 0; color: #5a6e5e; font-size: 0.85rem;\">Mencontoh semangat perjuangan pendiri (Bapak H. Mohammad Nur & Ibu Hj. Siti Wasri) dalam menuntut ilmu.</p>\r\n                </div>\r\n            </div>\r\n        </div>\r\n\r\n        <!-- Nilai Tambah / Daya Tarik Khusus -->\r\n        <div style=\"background: linear-gradient(115deg, #eef5ea, #e2ecdf); border-radius: 28px; padding: 28px 32px; margin: 25px 0 20px;\">\r\n            <div style=\"display: flex; align-items: center; gap: 12px; margin-bottom: 20px;\">\r\n                <i class=\"fas fa-gem\" style=\"color: #1e6b3e; font-size: 1.8rem;\"></i>\r\n                <h2 style=\"margin: 0; color: #1e3a2f; font-size: 1.3rem; font-weight: 700;\">Nilai Tambah & Daya Tarik Khusus</h2>\r\n            </div>\r\n            <div style=\"display: flex; flex-wrap: wrap; gap: 20px;\">\r\n                <div style=\"flex: 1; min-width: 250px;\">\r\n                    <div style=\"display: flex; gap: 12px; margin-bottom: 20px;\">\r\n                        <i class=\"fas fa-landmark\" style=\"color: #e6bc7e; font-size: 1.3rem;\"></i>\r\n                        <div>\r\n                            <h4 style=\"margin: 0 0 5px 0; color: #1e6b3e;\">Sejarah Perjuangan Nyata</h4>\r\n                            <p style=\"margin: 0; color: #4a624e; font-size: 0.85rem; line-height: 1.5;\">Pesantren ini bukan sekadar sekolah, melainkan lembaga yang lahir dari perjuangan memperbaiki kondisi sosial dan spiritual masyarakat Cipunagara.</p>\r\n                        </div>\r\n                    </div>\r\n                    <div style=\"display: flex; gap: 12px;\">\r\n                        <i class=\"fas fa-tree\" style=\"color: #e6bc7e; font-size: 1.3rem;\"></i>\r\n                        <div>\r\n                            <h4 style=\"margin: 0 0 5px 0; color: #1e6b3e;\">Lingkungan yang Terjaga</h4>\r\n                            <p style=\"margin: 0; color: #4a624e; font-size: 0.85rem; line-height: 1.5;\">Menawarkan suasana belajar yang tenang dan jauh dari hiruk-pikuk negatif, sangat cocok untuk pembentukan karakter putra-putri Anda.</p>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                <div style=\"flex: 1; min-width: 250px;\">\r\n                    <div style=\"display: flex; gap: 12px;\">\r\n                        <i class=\"fas fa-handshake\" style=\"color: #e6bc7e; font-size: 1.3rem;\"></i>\r\n                        <div>\r\n                            <h4 style=\"margin: 0 0 5px 0; color: #1e6b3e;\">Sinergi Pendidikan Lengkap</h4>\r\n                            <p style=\"margin: 0; color: #4a624e; font-size: 0.85rem; line-height: 1.5;\">Orang tua tidak perlu khawatir dengan pendidikan formal, karena anak tetap bisa meraih ijazah nasional melalui SMP Nusantara sambil tetap menjadi santri mukim.</p>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n\r\n        <!-- Footer Penutup -->\r\n        <div style=\"margin-top: 35px; padding-top: 20px; border-top: 1px solid #dee6da; text-align: center; font-size: 0.75rem; color: #7a927a; display: flex; flex-wrap: wrap; justify-content: center; gap: 28px;\">\r\n            <span><i class=\"fas fa-calendar-alt\"></i> Berdiri: 14 Januari 1996 M / 23 Sya\'ban 1416 H</span>\r\n            <span><i class=\"fas fa-tag\"></i> Nama Awal: PP Syarif Hidayatullah</span>\r\n            <span><i class=\"fas fa-mosque\"></i> Berubah Nama: 10 Januari 2015 M / 19 Rabiul Awal 1436 H</span>\r\n        </div>\r\n        <div style=\"text-align: center; margin-top: 20px; font-weight: 500; color: #2c6b48;\">\r\n            <i class=\"fas fa-star-and-crescent\"></i> Membumikan Al-Qur\'an dan Sunnah, Menebar Rahmat bagi Semesta <i class=\"fas fa-star-and-crescent\"></i>\r\n        </div>\r\n    </article>\r\n</section>\r\n\r\n<!-- Font Awesome CDN -->\r\n<link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.0.0-beta3/css/all.min.css\">', 'Publish', 'Jenjang', 'Program Haqi After School adalah inisiatif pendidikan untuk memperdalam pemahaman dan keterampilan membaca Al-Qur\'an setelah jam sekolah reguler.', '1774262375_1a4e121ba1340fa1b557.png', '', 22, 0, '2025-03-05 23:00:02', '2025-03-05 22:59:00', '2026-03-25 05:30:46');
INSERT INTO `jenjang_pendidikan` (`id_jenjang_pendidikan`, `id_user`, `id_jenjang`, `slug_jenjang_pendidikan`, `judul_jenjang_pendidikan`, `ringkasan`, `isi`, `status_jenjang_pendidikan`, `jenis_jenjang_pendidikan`, `keywords`, `gambar`, `icon`, `hits`, `urutan`, `tanggal_post`, `tanggal_publish`, `tanggal`) VALUES
(17, 11, 5, 'smp-nusantara-cipunagara', 'SMP NUSANTARA CIPUNAGARA', 'Di bawah naungan Yayasan Al-Hikamussalafie, SMP Nusantara Cipunagara hadir sejak Januari 2022 sebagai sekolah menengah pertama yang memadukan kurikulum nasional dengan nilai luhur pesantren untuk mencetak generasi unggul yang cerdas secara akademik dan kuat secara akhlak.', '<section id=\"profil-smp\" style=\"max-width: 1100px; margin: 0 auto; font-family: \'Segoe UI\', \'Poppins\', system-ui, -apple-system, sans-serif; background: #ffffff; border-radius: 28px; box-shadow: 0 20px 40px rgba(0,0,0,0.05); overflow: hidden;\">\r\n    \r\n    <!-- Header dengan gradien hijau tosca -->\r\n    <header style=\"background: linear-gradient(135deg, #1e6b3e, #2c9b6e, #1a7a5c); padding: 50px 30px 45px; text-align: center; color: white; position: relative;\">\r\n        <div style=\"position: absolute; top: 20px; right: 20px; opacity: 0.1; font-size: 80px;\">\r\n            <i class=\"fas fa-school\"></i>\r\n        </div>\r\n        <div style=\"font-size: 55px; margin-bottom: 15px;\">\r\n            <i class=\"fas fa-graduation-cap\" style=\"background: rgba(255,255,255,0.2); padding: 15px 22px; border-radius: 60px;\"></i>\r\n        </div>\r\n        <h1 style=\"font-size: 2.3rem; margin: 0 0 12px 0; font-weight: 700; letter-spacing: -0.5px;\">\r\n            SMP Nusantara Cipunagara\r\n        </h1>\r\n        <p style=\"font-size: 1rem; opacity: 0.95; margin: 0 auto; max-width: 550px; line-height: 1.5;\">\r\n            <i class=\"fas fa-quote-left\"></i> Memadukan Tradisi Pesantren dengan Pendidikan Modern <i class=\"fas fa-quote-right\"></i>\r\n        </p>\r\n        <div style=\"margin-top: 20px;\">\r\n            <span style=\"background: rgba(255,255,255,0.2); padding: 6px 18px; border-radius: 40px; font-size: 0.8rem;\">\r\n                <i class=\"fas fa-calendar-alt\"></i> Berdiri: 4 Januari 2022\r\n            </span>\r\n        </div>\r\n    </header>\r\n\r\n    <!-- Badge Informasi -->\r\n    <div style=\"display: flex; flex-wrap: wrap; gap: 20px; background: linear-gradient(95deg, #f8fafc, #f0f5f0); padding: 20px 30px; border-bottom: 1px solid #e2e8e6;\">\r\n        <div style=\"display: flex; align-items: center; gap: 12px;\">\r\n            <span style=\"background: #1e6b3e; width: 38px; height: 38px; display: inline-flex; align-items: center; justify-content: center; border-radius: 50%; color: white;\"><i class=\"fas fa-building\"></i></span>\r\n            <div>\r\n                <div style=\"font-size: 0.7rem; color: #5a7a6a;\">YAYASAN</div>\r\n                <div style=\"font-weight: 700; color: #1e5631;\">Al-Hikamussalafie</div>\r\n            </div>\r\n        </div>\r\n        <div style=\"display: flex; align-items: center; gap: 12px;\">\r\n            <span style=\"background: #1e6b3e; width: 38px; height: 38px; display: inline-flex; align-items: center; justify-content: center; border-radius: 50%; color: white;\"><i class=\"fas fa-user-tie\"></i></span>\r\n            <div>\r\n                <div style=\"font-size: 0.7rem; color: #5a7a6a;\">KEPALA SEKOLAH</div>\r\n                <div style=\"font-weight: 700; color: #1e5631;\">Hamdan Hidayat, S.H.</div>\r\n            </div>\r\n        </div>\r\n        <div style=\"display: flex; align-items: center; gap: 12px;\">\r\n            <span style=\"background: #1e6b3e; width: 38px; height: 38px; display: inline-flex; align-items: center; justify-content: center; border-radius: 50%; color: white;\"><i class=\"fas fa-map-marker-alt\"></i></span>\r\n            <div>\r\n                <div style=\"font-size: 0.7rem; color: #5a7a6a;\">LOKASI</div>\r\n                <div style=\"font-weight: 700; color: #1e5631;\">Cipunagara, Subang</div>\r\n            </div>\r\n        </div>\r\n    </div>\r\n\r\n    <!-- Konten Utama -->\r\n    <article style=\"padding: 35px 32px; background: #ffffff;\">\r\n        \r\n        <!-- 1) Sejarah Singkat -->\r\n        <div style=\"margin-bottom: 40px;\">\r\n            <div style=\"display: flex; align-items: center; gap: 12px; margin-bottom: 18px; border-left: 4px solid #1e6b3e; padding-left: 18px;\">\r\n                <i class=\"fas fa-history\" style=\"color: #1e6b3e; font-size: 1.6rem;\"></i>\r\n                <h2 style=\"margin: 0; color: #1e3a2f; font-size: 1.5rem; font-weight: 600;\">Sejarah Singkat</h2>\r\n            </div>\r\n            <p style=\"line-height: 1.75; text-align: justify; color: #2d3e32; margin-bottom: 15px;\">\r\n                <strong>SMP Nusantara Cipunagara</strong> merupakan satuan pendidikan di bawah naungan \r\n                <strong>Yayasan Al-Hikamussalafie</strong> yang lahir dari semangat integrasi antara ilmu agama dan ilmu umum. \r\n                Berdiri sebagai jawaban atas aspirasi wali santri dan masyarakat, sekolah ini hadir untuk memastikan \r\n                setiap generasi memiliki bekal intelektual formal tanpa meninggalkan akar spiritualitas pesantren.\r\n            </p>\r\n            <p style=\"line-height: 1.75; text-align: justify; color: #2d3e32;\">\r\n                Lahir dari rahim perjuangan <strong>Pondok Pesantren Al-Hikamussalafie</strong> (sebelumnya bernama \r\n                Syarif Hidayatullah), gagasan pendirian SMP ini muncul pada <strong>Januari 2022</strong>. Didorong oleh \r\n                visi besar untuk memajukan pendidikan di wilayah Cipunagara, sekolah ini resmi memulai \r\n                <strong>Kegiatan Belajar Mengajar (KBM) pada 4 Januari 2022</strong>. Di bawah kepemimpinan kepala sekolah pertama, \r\n                <strong>Bpk. Hamdan Hidayat, S.H.</strong>, SMP Nusantara Cipunagara berkomitmen menjadi jembatan bagi para santri \r\n                dan warga sekitar untuk meraih masa depan yang gemilang.\r\n            </p>\r\n        </div>\r\n\r\n        <!-- 2) Visi & Misi dengan layout grid -->\r\n        <div style=\"margin-bottom: 40px;\">\r\n            <div style=\"display: flex; align-items: center; gap: 12px; margin-bottom: 20px; border-left: 4px solid #e6bc7e; padding-left: 18px;\">\r\n                <i class=\"fas fa-bullseye\" style=\"color: #e6bc7e; font-size: 1.6rem;\"></i>\r\n                <h2 style=\"margin: 0; color: #1e3a2f; font-size: 1.5rem; font-weight: 600;\">Visi & Misi</h2>\r\n            </div>\r\n            <div style=\"background: #f9fcf9; border-radius: 24px; padding: 25px; border: 1px solid #e2eedb;\">\r\n                <div style=\"margin-bottom: 28px;\">\r\n                    <h3 style=\"color: #1e6b3e; margin-bottom: 12px; display: flex; align-items: center; gap: 8px;\">\r\n                        <i class=\"fas fa-eye\"></i> Visi\r\n                    </h3>\r\n                    <p style=\"font-style: italic; color: #3a5a48; font-size: 1rem; line-height: 1.6; margin: 0; padding-left: 20px; border-left: 3px solid #e6bc7e;\">\r\n                        \"Mewujudkan Generasi Unggul yang Berwawasan Luas, Berkarakter Islami, dan Berbakti pada Negeri.\"\r\n                    </p>\r\n                </div>\r\n                <div>\r\n                    <h3 style=\"color: #1e6b3e; margin-bottom: 12px; display: flex; align-items: center; gap: 8px;\">\r\n                        <i class=\"fas fa-list-check\"></i> Misi\r\n                    </h3>\r\n                    <ul style=\"list-style-type: none; padding-left: 0; margin: 0;\">\r\n                        <li style=\"margin-bottom: 12px; display: flex; gap: 12px; align-items: flex-start;\">\r\n                            <i class=\"fas fa-check-circle\" style=\"color: #27ae60; margin-top: 3px;\"></i>\r\n                            <span style=\"color: #2d3e32;\">Menyelenggarakan pendidikan formal yang selaras dengan nilai-nilai luhur pesantren.</span>\r\n                        </li>\r\n                        <li style=\"margin-bottom: 12px; display: flex; gap: 12px; align-items: flex-start;\">\r\n                            <i class=\"fas fa-check-circle\" style=\"color: #27ae60; margin-top: 3px;\"></i>\r\n                            <span style=\"color: #2d3e32;\">Membangun kedisiplinan, kemandirian, dan etika sosial (Adabul Karimah) pada peserta didik.</span>\r\n                        </li>\r\n                        <li style=\"margin-bottom: 12px; display: flex; gap: 12px; align-items: flex-start;\">\r\n                            <i class=\"fas fa-check-circle\" style=\"color: #27ae60; margin-top: 3px;\"></i>\r\n                            <span style=\"color: #2d3e32;\">Mengembangkan potensi akademik dan kreativitas siswa melalui lingkungan belajar yang inklusif.</span>\r\n                        </li>\r\n                        <li style=\"margin-bottom: 12px; display: flex; gap: 12px; align-items: flex-start;\">\r\n                            <i class=\"fas fa-check-circle\" style=\"color: #27ae60; margin-top: 3px;\"></i>\r\n                            <span style=\"color: #2d3e32;\">Memperkuat sinergi antara sekolah, orang tua, dan masyarakat sekitar.</span>\r\n                        </li>\r\n                    </ul>\r\n                </div>\r\n            </div>\r\n        </div>\r\n\r\n        <!-- 3) Program Unggulan dengan grid card -->\r\n        <div style=\"margin-bottom: 40px;\">\r\n            <div style=\"display: flex; align-items: center; gap: 12px; margin-bottom: 20px; border-left: 4px solid #1e6b3e; padding-left: 18px;\">\r\n                <i class=\"fas fa-star\" style=\"color: #1e6b3e; font-size: 1.6rem;\"></i>\r\n                <h2 style=\"margin: 0; color: #1e3a2f; font-size: 1.5rem; font-weight: 600;\">Program Unggulan</h2>\r\n            </div>\r\n            <div style=\"display: flex; flex-wrap: wrap; gap: 20px;\">\r\n                <div style=\"flex: 1; min-width: 240px; background: #fefaf2; border-radius: 20px; padding: 22px; border: 1px solid #f0e5d4;\">\r\n                    <div style=\"background: #1e6b3e20; width: 50px; height: 50px; border-radius: 16px; display: flex; align-items: center; justify-content: center; margin-bottom: 15px;\">\r\n                        <i class=\"fas fa-book-quran\" style=\"color: #1e6b3e; font-size: 1.5rem;\"></i>\r\n                    </div>\r\n                    <h3 style=\"margin: 0 0 10px 0; color: #1e6b3e; font-size: 1.1rem;\">Integrasi Kurikulum Pesantren</h3>\r\n                    <p style=\"margin: 0; color: #5a6e5e; line-height: 1.5; font-size: 0.9rem;\">Pembelajaran umum yang diperkuat dengan pendalaman kitab kuning dan nilai-nilai salafiah.</p>\r\n                </div>\r\n                <div style=\"flex: 1; min-width: 240px; background: #fefaf2; border-radius: 20px; padding: 22px; border: 1px solid #f0e5d4;\">\r\n                    <div style=\"background: #1e6b3e20; width: 50px; height: 50px; border-radius: 16px; display: flex; align-items: center; justify-content: center; margin-bottom: 15px;\">\r\n                        <i class=\"fas fa-quran\" style=\"color: #1e6b3e; font-size: 1.5rem;\"></i>\r\n                    </div>\r\n                    <h3 style=\"margin: 0 0 10px 0; color: #1e6b3e; font-size: 1.1rem;\">Tahfidz & Tahsin Al-Qur\'an</h3>\r\n                    <p style=\"margin: 0; color: #5a6e5e; line-height: 1.5; font-size: 0.9rem;\">Program bimbingan membaca dan menghafal Al-Qur\'an secara intensif.</p>\r\n                </div>\r\n                <div style=\"flex: 1; min-width: 240px; background: #fefaf2; border-radius: 20px; padding: 22px; border: 1px solid #f0e5d4;\">\r\n                    <div style=\"background: #1e6b3e20; width: 50px; height: 50px; border-radius: 16px; display: flex; align-items: center; justify-content: center; margin-bottom: 15px;\">\r\n                        <i class=\"fas fa-users\" style=\"color: #1e6b3e; font-size: 1.5rem;\"></i>\r\n                    </div>\r\n                    <h3 style=\"margin: 0 0 10px 0; color: #1e6b3e; font-size: 1.1rem;\">Pembinaan Karakter & Kepemimpinan</h3>\r\n                    <p style=\"margin: 0; color: #5a6e5e; line-height: 1.5; font-size: 0.9rem;\">Melalui organisasi kesiswaan dan kegiatan ekstrakurikuler yang aktif.</p>\r\n                </div>\r\n                <div style=\"flex: 1; min-width: 240px; background: #fefaf2; border-radius: 20px; padding: 22px; border: 1px solid #f0e5d4;\">\r\n                    <div style=\"background: #1e6b3e20; width: 50px; height: 50px; border-radius: 16px; display: flex; align-items: center; justify-content: center; margin-bottom: 15px;\">\r\n                        <i class=\"fas fa-hand-holding-heart\" style=\"color: #1e6b3e; font-size: 1.5rem;\"></i>\r\n                    </div>\r\n                    <h3 style=\"margin: 0 0 10px 0; color: #1e6b3e; font-size: 1.1rem;\">Local Wisdom & Community Project</h3>\r\n                    <p style=\"margin: 0; color: #5a6e5e; line-height: 1.5; font-size: 0.9rem;\">Melibatkan siswa dalam kegiatan sosial dan kemasyarakatan di lingkungan Cipunagara.</p>\r\n                </div>\r\n            </div>\r\n        </div>\r\n\r\n        <!-- 4) Kurikulum & Lingkungan Belajar -->\r\n        <div style=\"margin-bottom: 40px; display: flex; flex-wrap: wrap; gap: 25px;\">\r\n            <div style=\"flex: 1; min-width: 260px; background: #f6f9f3; border-radius: 24px; padding: 22px;\">\r\n                <div style=\"display: flex; align-items: center; gap: 10px; margin-bottom: 15px;\">\r\n                    <i class=\"fas fa-book-open\" style=\"color: #1e6b3e; font-size: 1.5rem;\"></i>\r\n                    <h3 style=\"margin: 0; color: #1e6b3e;\">Kurikulum Nasional Terpadu</h3>\r\n                </div>\r\n                <p style=\"color: #4a624e; line-height: 1.6; margin: 0;\">Mengacu pada standar nasional dengan pendekatan pembelajaran aktif dan inovatif.</p>\r\n            </div>\r\n            <div style=\"flex: 1; min-width: 260px; background: #f6f9f3; border-radius: 24px; padding: 22px;\">\r\n                <div style=\"display: flex; align-items: center; gap: 10px; margin-bottom: 15px;\">\r\n                    <i class=\"fas fa-tree\" style=\"color: #1e6b3e; font-size: 1.5rem;\"></i>\r\n                    <h3 style=\"margin: 0; color: #1e6b3e;\">Lingkungan Islami yang Kondusif</h3>\r\n                </div>\r\n                <p style=\"color: #4a624e; line-height: 1.6; margin: 0;\">Terletak di kawasan pesantren yang tenang, mendukung fokus belajar dan pembentukan akhlak.</p>\r\n            </div>\r\n            <div style=\"flex: 1; min-width: 260px; background: #f6f9f3; border-radius: 24px; padding: 22px;\">\r\n                <div style=\"display: flex; align-items: center; gap: 10px; margin-bottom: 15px;\">\r\n                    <i class=\"fas fa-file-alt\" style=\"color: #1e6b3e; font-size: 1.5rem;\"></i>\r\n                    <h3 style=\"margin: 0; color: #1e6b3e;\">Legalitas & Dukungan Lingkungan</h3>\r\n                </div>\r\n                <p style=\"color: #4a624e; line-height: 1.6; margin: 0;\">Memiliki izin resmi dan dukungan penuh dari tokoh masyarakat serta sinergi dengan SMPN Cipunagara.</p>\r\n            </div>\r\n        </div>\r\n\r\n        <!-- Mengapa Memilih -->\r\n        <div style=\"background: linear-gradient(105deg, #eef6ea, #e2f0e2); border-radius: 28px; padding: 30px 32px; margin-top: 20px;\">\r\n            <div style=\"display: flex; align-items: center; gap: 12px; margin-bottom: 18px;\">\r\n                <i class=\"fas fa-question-circle\" style=\"color: #1e6b3e; font-size: 1.8rem;\"></i>\r\n                <h2 style=\"margin: 0; color: #1e3a2f; font-size: 1.4rem; font-weight: 700;\">Mengapa Memilih SMP Nusantara Cipunagara?</h2>\r\n            </div>\r\n            <p style=\"line-height: 1.7; color: #2d4a3a; text-align: justify; margin-bottom: 0;\">\r\n                Kami memahami bahwa pendidikan adalah investasi terbaik. Di SMP Nusantara Cipunagara, putra-putri Anda \r\n                tidak hanya dididik untuk pintar secara akademik, tetapi juga dibimbing untuk memiliki integritas moral \r\n                yang kuat. Kami menawarkan solusi bagi orang tua yang menginginkan anaknya menempuh pendidikan SMP \r\n                namun tetap mendapatkan bekal agama yang mendalam di bawah asuhan \r\n                <strong>Yayasan Al-Hikamussalafie</strong>.\r\n            </p>\r\n        </div>\r\n\r\n        <!-- Footer Penutup -->\r\n        <div style=\"margin-top: 35px; padding-top: 20px; border-top: 1px solid #dce6dc; text-align: center; font-size: 0.75rem; color: #7a927a; display: flex; flex-wrap: wrap; justify-content: center; gap: 28px;\">\r\n            <span><i class=\"fas fa-calendar-check\"></i> Berdiri: 4 Januari 2022</span>\r\n            <span><i class=\"fas fa-chalkboard-user\"></i> Kepala Sekolah: Hamdan Hidayat, S.H.</span>\r\n            <span><i class=\"fas fa-handshake\"></i> Berkolaborasi dengan SMPN Cipunagara</span>\r\n        </div>\r\n        <div style=\"text-align: center; margin-top: 20px; font-weight: 500; color: #2c6b48;\">\r\n            <i class=\"fas fa-leaf\"></i> Menjadi Jembatan Generasi yang Berilmu, Beriman, dan Berbakti <i class=\"fas fa-leaf\"></i>\r\n        </div>\r\n    </article>\r\n</section>\r\n\r\n<!-- Font Awesome CDN -->\r\n<link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.0.0-beta3/css/all.min.css\">', 'Publish', 'Jenjang', '', '1773152523_20cff565aeac72df9807.png', '', 43, 1, '2026-03-09 12:10:32', '2026-03-09 12:10:00', '2026-03-25 05:30:08');
