INSERT INTO `konfigurasi` (`id_konfigurasi`, `id_user`, `namaweb`, `singkatan`, `tagline`, `tentang`, `deskripsi`, `website`, `email`, `email_cadangan`, `alamat`, `telepon`, `whatsapp`, `pesan_whatsapp`, `hp`, `logo`, `icon`, `keywords`, `metatext`, `facebook`, `tiktok`, `instagram`, `youtube`, `nama_facebook`, `nama_twitter`, `nama_instagram`, `nama_youtube`, `google_map`, `protocol`, `smtp_host`, `smtp_port`, `smtp_timeout`, `smtp_user`, `smtp_pass`, `paginasi`, `paginasi_depan`, `banner`, `link_text`, `link_website`, `link_video`, `ringkasan`, `fitur_pendaftaran`, `mulai_pendaftaran`, `selesai_pendaftaran`, `pengumuman_pendaftaran`, `keterangan_pendaftaran`, `menu_home`, `menu_berita`, `menu_profil`, `menu_prestasi`, `menu_galeri`, `menu_unduhan`, `menu_tautan`, `menu_kontak`, `menu_jenjang`, `letak_menu`, `login`, `tanggal`, `nama_tiktok`) VALUES
(1, 11, 'PESANTREN AL-HIKAMUSSALAFIE', 'ALHIKAM', 'Bersama Mewujudkan Generasi Qurani yang Mandiri dan Berakhlak Mulia', '<p><strong>Pondok Pesantren Al Hikamussalafie</strong> merupakan lembaga pendidikan Islam yang berfokus pada \r\n            pembinaan akhlak, pengembangan ilmu keislaman, serta pembentukan generasi muslim yang berilmu. \r\n            Lembaga ini berdiri sebagai pusat pendidikan dan dakwah yang berlandaskan pada <span style=\"color: #black; font-weight: bold;\">Al-Qur’an, Sunnah Nabi Muhammad SAW, serta tradisi keilmuan ulama salaf.</span></p>\r\n    </article>\r\n\r\n    <hr style=\"border: 0; border-top: 1px solid #eee; margin: 40px 0;\">\r\n\r\n    <div style=\"display: flex; gap: 20px; flex-wrap: wrap;\">\r\n        \r\n        <div style=\"flex: 1; min-width: 300px; padding: 20px; background: #DEB887; border-radius: 8px;\">\r\n            <h3>Kurikulum Salaf</h3>\r\n            <ul style=\"list-style-type: square; padding-left: 20px;\">\r\n                <li>Kajian Kitab Klasik (Kitab Kuning)</li>\r\n                <li>Tahsin & Tahfidz Al-Qur’an</li>\r\n                <li>Ilmu Alat: <em>Nahwu & Shorof</em></li>\r\n                <li>Dasar Keislaman: <em>Fiqih, Tauhid, & Akhlak</em></li>\r\n            </ul>\r\n        </div>\r\n\r\n        <div style=\"flex: 1; min-width: 300px; padding: 20px; background: #DEB887; border-radius: 8px;\">\r\n            <h3>Metode Pengajaran</h3>\r\n            <ul style=\"list-style-type: square; padding-left: 20px;\">\r\n                <li><strong>Bandongan:</strong> Pengajian kolektif</li>\r\n                <li><strong>Sorogan:</strong> Bimbingan intensif perorangan</li>\r\n                <li><strong>Disiplin:</strong> Pembinaan karakter & tanggung jawab</li>\r\n            </ul>\r\n        </div>\r\n\r\n    </div>\r\n\r\n    <footer style=\"margin-top: 40px; padding: 20px; border-left: 5px solid #27ae60; background: #DEB887;\">\r\n        <h4 style=\"margin-top: 0;\">Sinergi Pendidikan Formal</h4>\r\n        <p>\r\n            Di bawah naungan <strong>Yayasan Al Hikamussalafie</strong>, kami terus berinovasi tanpa meninggalkan tradisi. \r\n            Salah satu bentuk kontribusi nyata kami bagi masyarakat adalah pengembangan lembaga formal \r\n            <strong>SMP Nusantara Cipunagara</strong>.\r\n        </p>\r\n    </footer>\r\n\r\n    <div style=\"text-align: center; margin-top: 50px; font-weight: bold;\">\r\n        <p>Menuju Generasi Muslim yang Rahmatan Lil ‘Alamin</p>\r\n    </div>\r\n</section>', 'Bersama PESANTREN AL HIKAMUSSALAFIE, kami berkomitmen menghadirkan pendidikan berbasis Al-Qur\'an guna membentuk generasi Qurani yang berakhlak mulia, mandiri, serta siap menjadi pemimpin masa depan.', 'http://localhost:8080/alhikam', 'alhikam@gmail.com', 'alhikam@gmail.com', 'Tanjung, \r\nKec. Cipunagara, \r\nKabupaten Subang, Jawa Barat 41257', '085860009319', '085860009319', 'Halo min, saya tertarik dengan sekolah Anda.', '085860009319', '1773155513_8d872f635dfdb812adee.png', '1773118935_0fe0ffbd7c5e80586276.png', 'Rental Komputer Jakarta - Sewa Laptop, Printer, iPad, Scanner Barcode\r\n', '', 'https://www.facebook.com/share/1CAYPVq41M/', 'https://www.tiktok.com/@ponpes_alhikamussalafie?_r=1&_t=ZS-94ccBUkVvDZ', 'https://www.instagram.com/ponpes_alhikamussalafie?igsh=bWd4emJmNXRpaHMz', 'https://youtube.com/@alhikamussalafie?si=qS0kW3GSCoItxf50', 'PESANTREN AL-HIKAMUSSALAFIE', NULL, 'PESANTREN AL-HIKAMUSSALAFIE', 'PESANTREN AL-HIKAMUSSALAFIE', '<iframe src=\"https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3964.355112470238!2d107.890582!3d-6.4766268!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x2e69370f9e716579%3A0xe1b10321482e10a6!2sYayasan%20Pondok%20Pesantren%20Alhikamussalafie!5e0!3m2!1sen!2sid!4v1773058455530!5m2!1sen!2sid\" width=\"600\" height=\"450\" style=\"border:0;\" allowfullscreen=\"\" loading=\"lazy\" referrerpolicy=\"no-referrer-when-downgrade\"></iframe>', 'smtp', 'ssl://mail.haqi.sch.id', 465, 7, 'ppdb@haqi.sch.id', 'Rasulullah125710', 25, 25, '1774370410_cc3c788c2a3116548035.jpeg', 'Lihat Profil Lengkap Kami', 'profil', 'https://youtu.be/RZSBYMtwyDo?si=TDW3ztLAkiB4r6bn', 'Selamat Datang <br>di Pesantren Al-Hikamussalafie', 'On', '2026-01-01', '2026-12-01', '2026-12-31', '<p>Silakan melakukan pendaftaran online sesuai jadwal.</p>', 'Publish', 'Publish', 'Publish', 'Publish', 'Publish', 'Publish', 'Publish', 'Publish', 'Publish', 'Galeri', '1773181148_3a6f04d3f4c7a9ca9c78.png', '2026-03-24 16:40:10', 'PESANTREN AL-HIKAMUSSALAFIE');
